                       ( DMX.IS_MULTIPHASE = 'Y' AND TRIM(DMX.MLT_INDEX_LABEL_SIDE1) IS NULL)
                       OR
                       ( NVL(DMX.TRC_FIX_FLOAT_RATE_IND,DMX.TRP_FIX_FLOAT_RATE_IND_NEAR) = 'F')
                     )

            THEN

                CASE
                    WHEN (DMX.THD_ZERO_COUPON_IND='Y' OR DMX.CNT_FFL_FLOW_PYMT_DATE_NEAR_INT = 1) THEN '1'
                    WHEN DMX.IS_MULTIPHASE = 'Y' THEN TO_CHAR(DECODE(UPPER(DMX.MLT_PAYM_PERIOD_UNIT_SIDE1),'TRIMESTER',3,'QUARTER',3,'SEMESTER',6,1) * DMX.MLT_PAYM_PERIOD_MULTIP_SIDE1)
                    ELSE REGEXP_SUBSTR(DMX.THD_PAYMT_FREQ_VAL, '^\d+')
                END


            ELSE NULL
        END AS FIX_PMT_FREQ_MULTI_LEG1,

        CASE
            WHEN DMX.THD_FGT_GRP = 'RTRN' AND UPI LIKE 'Credit%' AND DMX.TRP_FIX_FLOAT_RATE_IND_FAR = 'F' THEN
                CASE
                    WHEN DMX.CNT_FFL_FLOW_PYMT_DATE_FAR_INT = 1 THEN '1'
                    WHEN UPPER(DMX.TRP_LEG_PYMT_FREQ_VAL_FAR) IN('1D','1W','1M','1Y','ZC','8000D','8000OD','30Y','2000Y') THEN '1'
                    WHEN UPPER(DMX.TRP_LEG_PYMT_FREQ_VAL_FAR) = '6M' THEN '6'
                    WHEN UPPER(DMX.TRP_LEG_PYMT_FREQ_VAL_FAR) = '3M' THEN '3'
                    WHEN UPPER(DMX.TRP_LEG_PYMT_FREQ_VAL_FAR) = '2W' THEN '14'
                    WHEN UPPER(DMX.TRP_LEG_PYMT_FREQ_VAL_FAR) = '4W' THEN '28'
                    ELSE REGEXP_SUBSTR(DMX.TRP_LEG_PYMT_FREQ_VAL_FAR, '^\d+')
                END

            WHEN DMX.THD_FGT_GRP = 'TRS' AND UPI LIKE 'Credit%' AND DMX.TRP_FIX_FLOAT_RATE_IND_NEAR = 'F' THEN
                CASE
                    WHEN DMX.CNT_FFL_FLOW_PYMT_DATE_NEAR = 1 THEN '1'
                    WHEN UPPER(DMX.THD_PAYMT_FREQ_VAL) IN('1D','1W','1M','1Y','ZC','8000D','8000OD','30Y','2000Y') THEN '1'
                    WHEN UPPER(DMX.THD_PAYMT_FREQ_VAL) = '6M' THEN '6'
                    WHEN UPPER(DMX.THD_PAYMT_FREQ_VAL) = '3M' THEN '3'
                    WHEN UPPER(DMX.THD_PAYMT_FREQ_VAL) = '2W' THEN '14'
                    WHEN UPPER(DMX.THD_PAYMT_FREQ_VAL) = '4W' THEN '28'
                    ELSE REGEXP_SUBSTR(DMX.THD_PAYMT_FREQ_VAL, '^\d+')
                END

            WHEN DMX.THD_TRD_CLASS_SRC_NAME IN ('IRD_IRS','IRD_CS')
                 AND
                 DMX.THD_CONTRCT_TYPOLOGY_VAL LIKE 'CR Link%'
                 AND (
                       ( DMX.IS_MULTIPHASE = 'Y' AND TRIM(DMX.MLT_INDEX_LABEL_SIDE2) IS NULL)
                       OR
                       ( DMX.TRP_FIX_FLOAT_RATE_IND_FAR = 'F')
                     )

            THEN

                CASE
                    WHEN (DMX.THD_ZERO_COUPON_IND='Y' OR DMX.CNT_FFL_FLOW_PYMT_DATE_NEAR_INT = 1) THEN '1'
                    WHEN DMX.IS_MULTIPHASE = 'Y' THEN TO_CHAR(DECODE(UPPER(DMX.MLT_PAYM_PERIOD_UNIT_SIDE2),'TRIMESTER',3,'QUARTER',3,'SEMESTER',6,1) * MLT_PAYM_PERIOD_MULTIP_SIDE2)
                    ELSE REGEXP_SUBSTR(DMX.TRP_LEG_PYMT_FREQ_VAL_FAR, '^\d+')
                END

            ELSE NULL
        END AS FIX_PMT_FREQ_MULTI_LEG2,

        CASE
            WHEN (DMX.THD_TRD_CLASS_SRC_NAME LIKE 'CRD%' OR (DMX.THD_FGT_GRP = 'RTRN' AND UPI LIKE 'Credit%')) AND NVL(DMX.TRC_FIX_FLOAT_RATE_IND,DMX.TRP_FIX_FLOAT_RATE_IND_NEAR) = 'V' THEN
                CASE
                    WHEN DMX.CNT_FFL_FLOW_PYMT_DATE_NEAR_INT = 1 THEN '1'
                    WHEN UPPER(DMX.THD_PAYMT_FREQ_VAL) IN ('1D','1W','1M','1Y','ZC','8000D','8000OD','30Y','2000Y')  THEN '1'
                    WHEN UPPER(DMX.THD_PAYMT_FREQ_VAL) = '6M' THEN '6'
                    WHEN UPPER(DMX.THD_PAYMT_FREQ_VAL) = '3M' THEN '3'
                    WHEN UPPER(DMX.THD_PAYMT_FREQ_VAL) = '2W' THEN '14'
                    WHEN UPPER(DMX.THD_PAYMT_FREQ_VAL) = '4W' THEN '28'
                    ELSE REGEXP_SUBSTR(DMX.THD_PAYMT_FREQ_VAL, '^\d+')
                END
            WHEN DMX.THD_FGT_GRP = 'TRS' AND UPI LIKE 'Credit%' AND DMX.TRP_FIX_FLOAT_RATE_IND_FAR = 'V' THEN
                CASE
                    WHEN DMX.CNT_FFL_FLOW_PYMT_DATE_FAR = 1 THEN '1'
                    WHEN UPPER(DMX.TRP_LEG_PYMT_FREQ_VAL_FAR) IN('1D','1W','1M','1Y','ZC','8000D','8000OD','30Y','2000Y') THEN '1'
                    WHEN UPPER(DMX.TRP_LEG_PYMT_FREQ_VAL_FAR) = '6M' THEN '6'
                    WHEN UPPER(DMX.TRP_LEG_PYMT_FREQ_VAL_FAR) = '3M' THEN '3'
                    WHEN UPPER(DMX.TRP_LEG_PYMT_FREQ_VAL_FAR) = '2W' THEN '14'
                    WHEN UPPER(DMX.TRP_LEG_PYMT_FREQ_VAL_FAR) = '4W' THEN '28'
                    ELSE REGEXP_SUBSTR(DMX.TRP_LEG_PYMT_FREQ_VAL_FAR, '^\d+')
                  END
			WHEN DMX.THD_TRD_CLASS_SRC_NAME IN ('IRD_IRS','IRD_CS')
                 AND
                 DMX.THD_CONTRCT_TYPOLOGY_VAL LIKE 'CR Link%'
                 AND (
                       ( DMX.IS_MULTIPHASE = 'Y' AND TRIM(DMX.MLT_INDEX_LABEL_SIDE1) IS NULL)
                       OR
                       ( NVL(DMX.TRC_FIX_FLOAT_RATE_IND,DMX.TRP_FIX_FLOAT_RATE_IND_NEAR) = 'V')
                     )
            THEN
                CASE
                    WHEN DMX.CNT_FFL_FLOW_PYMT_DATE_NEAR_INT = 1 THEN '1'
                    WHEN DMX.THD_ZERO_COUPON_IND='Y'  THEN '1'
                    WHEN DMX.IS_MULTIPHASE = 'Y' THEN TO_CHAR(DECODE(UPPER(DMX.MLT_PAYM_PERIOD_UNIT_SIDE1),'TRIMESTER',3,'QUARTER',3,'SEMESTER',6,1) * MLT_CALC_PERIOD_MULTIP_SIDE1)
                    ELSE REGEXP_SUBSTR(DMX.THD_PAYMT_FREQ_VAL, '^\d+')
                END
            ELSE NULL
        END AS FLOAT_PMT_FREQ_MULTI_LEG1,

        CASE
            WHEN DMX.THD_FGT_GRP = 'RTRN' AND UPI LIKE 'Credit%' AND DMX.TRP_FIX_FLOAT_RATE_IND_FAR = 'V' THEN
                CASE
                    WHEN DMX.CNT_FFL_FLOW_PYMT_DATE_FAR_INT = 1 THEN '1'
                    WHEN UPPER(DMX.TRP_LEG_PYMT_FREQ_VAL_FAR) IN('1D','1W','1M','1Y','ZC','8000D','8000OD','30Y','2000Y') THEN '1'
                    WHEN UPPER(DMX.TRP_LEG_PYMT_FREQ_VAL_FAR) = '6M' THEN '6'
                    WHEN UPPER(DMX.TRP_LEG_PYMT_FREQ_VAL_FAR) = '3M' THEN '3'
                    WHEN UPPER(DMX.TRP_LEG_PYMT_FREQ_VAL_FAR) = '2W' THEN '14'
                    WHEN UPPER(DMX.TRP_LEG_PYMT_FREQ_VAL_FAR) = '4W' THEN '28'
                    ELSE REGEXP_SUBSTR(DMX.TRP_LEG_PYMT_FREQ_VAL_FAR, '^\d+')
                END
            WHEN DMX.THD_FGT_GRP = 'TRS' AND UPI LIKE 'Credit%' AND DMX.TRP_FIX_FLOAT_RATE_IND_NEAR = 'V' THEN
                CASE
                    WHEN DMX.CNT_FFL_FLOW_PYMT_DATE_NEAR = 1 THEN '1'
                    WHEN UPPER(DMX.THD_PAYMT_FREQ_VAL) IN('1D','1W','1M','1Y','ZC','8000D','8000OD','30Y','2000Y') THEN '1'
					WHEN UPPER(DMX.THD_PAYMT_FREQ_VAL) = '6M' THEN '6'
                    WHEN UPPER(DMX.THD_PAYMT_FREQ_VAL) = '3M' THEN '3'
                    WHEN UPPER(DMX.THD_PAYMT_FREQ_VAL) = '2W' THEN '14'
                    WHEN UPPER(DMX.THD_PAYMT_FREQ_VAL) = '4W' THEN '28'
                    ELSE REGEXP_SUBSTR(DMX.THD_PAYMT_FREQ_VAL, '^\d+')
                END
			WHEN DMX.THD_TRD_CLASS_SRC_NAME IN ('IRD_IRS','IRD_CS')
                 AND
                 DMX.THD_CONTRCT_TYPOLOGY_VAL LIKE 'CR Link%'
                 AND (
                       ( DMX.IS_MULTIPHASE = 'Y' AND TRIM(DMX.MLT_INDEX_LABEL_SIDE2) IS NULL)
                       OR
                       ( DMX.TRP_FIX_FLOAT_RATE_IND_FAR = 'V')
                     )
            THEN
                CASE
                    WHEN DMX.CNT_FFL_FLOW_PYMT_DATE_FAR_INT = 1 THEN '1'
                    WHEN DMX.THD_ZERO_COUPON_IND='Y'  THEN '1'
                    WHEN DMX.IS_MULTIPHASE = 'Y' THEN TO_CHAR(DECODE(UPPER(DMX.MLT_PAYM_PERIOD_UNIT_SIDE2),'TRIMESTER',3,'QUARTER',3,'SEMESTER',6,1) * MLT_CALC_PERIOD_MULTIP_SIDE2)
                    ELSE REGEXP_SUBSTR(DMX.TRP_LEG_PYMT_FREQ_VAL_FAR, '^\d+')
                END
            ELSE NULL
        END AS FLOAT_PMT_FREQ_MULTI_LEG2,

