            ELSE NULL
        END AS INDEX_FACTOR,

        DMX.EMBEDDED_OPT,

        TO_CHAR
        (
            CASE
                WHEN DMX.THD_TRD_CLASS_SRC_NAME LIKE 'CRD%'
                THEN DMX.THD_UNADJST_MAT_DATE

                ELSE
                    NULLIF
                    (
                        GREATEST
                        (
                             NVL(DMX.MAX_FFL_PERIOD_END_DATE_NEAR_INT,TO_DATE('1900-01-01','YYYY-MM-DD'))
                            ,NVL(DMX.MAX_FFL_FLOW_UNADJST_PMT_DATE_NEAR_INT,TO_DATE('1900-01-01','YYYY-MM-DD'))
