            WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_IRS' AND DMX.UPI LIKE 'Credit%'  AND sub_delivery_type.UPI_DELIVERY_TYPE = 'CASH' THEN DMX.THD_NOMINAL_CCY_CODE
            WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_TRS' AND DMX.UPI LIKE 'Credit%' THEN DMX.TRP_FX_EQUIV_CCY_CODE_FAR
