            WHEN DMX.THD_FGT_GRP = 'IRS' AND DMX.UPI LIKE 'Credit%' AND sub_delivery_type.UPI_DELIVERY_TYPE = 'CASH'
            THEN DMX.TRP_SWAP_NOTIONAL_CCY_FAR

            WHEN DMX.THD_FGT_GRP = 'TRS' AND DMX.UPI LIKE 'Credit%'
            THEN DMX.TRP_FX_EQUIV_CCY_CODE_NEAR

