                    WHEN DMX.THD_FGT_GRP = 'IRS' AND DMX.THD_NOMINAL_CCY_CODE = 'CNH' THEN 'HK'
                    WHEN DMX.THD_FGT_GRP = 'TRS' AND DMX.TRP_FX_EQUIV_CCY_CODE_FAR = 'CNH' THEN 'HK'
                    ELSE NULL
                END
            ELSE NULL
        END SETTLEMENT_LOCATION_LEG1,

