        sub_underlier.UNDERLYING_SOURCE_LEG1 AS UNDERLYING_SOURCE_LEG1,

        CASE
            WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'CRD_CDS' THEN
                CASE
                    WHEN DMX.THD_TYPOLOGY_DESC = 'LCDS' THEN DMX.RPY_ENTITY_NAME_CTPY
                    WHEN DMX.THD_TYPOLOGY_DESC IN('NON Red - CDS','Bespoke CDS') OR DMX.THD_PKG_NAME = 'Risk Participation Agreement' THEN DMX.RPY_PTY_NAME_UNDERLY_ISSUER
                    ELSE DMX.RPY_PTY_NAME_INSTR_ISSUER
                END
            WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'CRD_CRDI' THEN DMX.RIN_DESC_INSTR
            WHEN DMX.THD_TRD_CLASS_SRC_NAME IN('IRD_IRS','IRD_CS') AND NVL(DMX.TRP_CREDIT_BSK_NATURE_NEAR,DMX.TRP_CREDIT_BSK_NATURE_FAR) = 'Index' THEN DMX.RIN_DESC_INSTR
            WHEN DMX.UPI LIKE 'Credit%' THEN
                CASE
                    WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_TRS' THEN
                        CASE
                            WHEN DMX.THD_PKG_NAME = 'TRS on MBS' THEN NULL
                            WHEN DMX.THD_SEC_GRP_VAL = 'Bond' THEN DMX.RPY_PTY_NAME_MAIN_IDX_ISSUER_LEFT_UNDERSCORE_FAR
                            ELSE NULL
                        END
                    WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_RTRN_SWAP' THEN
                        CASE
                            WHEN DMX.THD_PKG_NAME = 'TRS on MBS' THEN NULL
                            ELSE DMX.RIN_DESC_MAIN_IDX_LEFT_UNDERSCORE_NEAR
                        END
                    WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_RTRN_BSK' THEN
                        CASE
                            WHEN DMX.TRP_LEG_SEC_GRP_CODE_NEAR = 'Equity' AND DMX.TRP_LEG_SEC_TP_CODE_NEAR IN('Index','ETF','Basket') THEN DMX.RPY_PTY_NAME_MAIN_IDX_ISSUER_LEFT_UNDERSCORE_NEAR
                            ELSE NULL
                        END
                    ELSE NULL
                END
            ELSE NULL
        END AS UNDERLYING_ASSET_NAME,

        --<GH_Rewrite_Work>
        -- Ces champs ne peuvent plus  tre "communs" car utilisent des champs par asset-class dans leur formule! Molson salue les vrais!
--        DMX.MASTER_AGREEMENT_TYPE,
--		DMX.MASTER_AGREEMENT_VERSION,
        sub_agreement_type.MASTER_AGREEMENT_TYPE,
        DECODE(sub_agreement_type.MASTER_AGREEMENT_TYPE,'ISDA',DMX.MLG_VERSION,NULL) AS MASTER_AGREEMENT_VERSION,
		--<GH_Rewrite_Work>

		DMX.COLLATERALIZED,

		DMX.LOCAL_CPT_JURISDICTION2,

		DMX.INTER_AFFILIATE,

		DMX.BROKER_TYPE,

		DMX.BROKER_ID,

        DMX.EXECUTION_VENUE,

        DMX.EXECUTION_VENUE_TYPE,

		--<GH_Rewrite_Work>
--		CASE
--			WHEN DMX.THD_FAMILY = 'CRD' OR  DMX.THD_TRD_CLASS_SRC_NAME IN('IRD_IRS','IRD_CS') THEN 'Credit'
--			WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_TRS' OR DMX.THD_TRD_CLASS_SRC_NAME LIKE 'IRD_RTRN%' THEN
--				CASE
--					WHEN DMX.THD_CONTRCT_TYPOLOGY_VAL LIKE 'IR TRS%' AND DMX.THD_SEC_GRP_VAL = 'Bond' AND DMX.RPY_LEI_NO_ISSR = '254900HROIFWPRGM1V77' THEN 'Rates'
--					ELSE 'Credit'
--				END
--			ELSE NULL
--		END AS UPI_ASSET_CLASS,
		sub_upi_fields.UPI_ASSET_CLASS,
		--</GH_Rewrite_Work>

		sub_instrument.UPI_INSTRUMENT_TYPE AS UPI_INSTRUMENT_TYPE,

		'UPI' AS UPI_LEVEL,

		sub_product.UPI_PRODUCT AS UPI_PRODUCT,

		CAST (NULL AS VARCHAR2 (1 BYTE)) AS UPI_ADD_SUB_PRODUCT,

		CAST (NULL AS VARCHAR2 (1 BYTE)) AS UPI_BASE_PRODUCT,

		sub_contract_spec.UPI_CONTRACT_SPEC AS UPI_CONTRACT_SPEC,

		sub_debt_seniority.UPI_DEBT_SENIORITY AS UPI_DEBT_SENIORITY,

		sub_delivery_type.UPI_DELIVERY_TYPE AS UPI_DELIVERY_TYPE,

		CASE
			WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'CRD_CDS' AND NVL(DMX.THD_TYPOLOGY_DESC, ' ') NOT IN ('NON Red - CDS', 'LCDS','Bespoke CDS') THEN sub_underlier.UNDERLIER_ID_LEG1
			WHEN DMX.THD_TRD_CLASS_SRC_NAME IN ('IRD_TRS', 'IRD_RTRN_BSK') AND NVL(DMX.THD_PKG_TYPE, ' ') != 'TRS on MBS' AND sub_underlier.UNDERLYING_SOURCE_LEG1 = 'ISIN' THEN sub_underlier.UNDERLIER_ID_LEG1
			ELSE NULL
		END	AS UPI_INSTR_ISIN,

		CASE
			WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'CRD_CDS' AND DMX.THD_TYPOLOGY_DESC IN ('NON Red - CDS','LCDS','Bespoke CDS') THEN sub_underlier.UNDERLIER_ID_LEG1
			--WHEN DMX.THD_TRD_CLASS_SRC_NAME IN('IRD_IRS','IRD_CS') AND sub_underlier.UNDERLYING_SOURCE_LEG1 = 'LEI' THEN sub_underlier.UNDERLIER_ID_LEG1 -- pas requis finalement
			ELSE NULL
		END AS UPI_INSTR_LEI,

		CAST (NULL AS VARCHAR2 (1 BYTE)) AS UPI_NOTIONAL_CURR,

		CASE
			WHEN DMX.THD_TRD_CLASS_SRC_NAME IN ('IRD_TRS','IRD_RTRN_BSK') THEN DECODE(THD_NOTIONAL_SCHEDULE_CODE,'C','Constant','I','Increasing','Y','Custom','D','Amortizing',NULL)
			ELSE NULL
		END AS UPI_NOTIONAL_SCHEDULE,

		CAST (NULL AS VARCHAR2 (1 BYTE)) AS UPI_OPTION_EXERCISE_STYLE,

		CAST (NULL AS VARCHAR2 (1 BYTE)) AS UPI_OPTION_TYPE,

		CAST (NULL AS VARCHAR2 (1 BYTE)) AS UPI_OTHR_ADD_SUB_PRODUCT,

		CAST (NULL AS VARCHAR2 (1 BYTE)) AS UPI_OTHR_BASE_PRODUCT,

		CAST (NULL AS VARCHAR2 (1 BYTE)) AS UPI_OTHR_LEG_REF_RATE,

		CAST (NULL AS VARCHAR2 (1 BYTE)) AS UPI_OTHR_LEG_REF_RATE_TRM_UNT,

		CAST (NULL AS VARCHAR2 (1 BYTE)) AS UPI_OTHR_LEG_REF_RATE_TRM_VAL,

		CAST (NULL AS VARCHAR2 (1 BYTE)) AS UPI_OTHR_LEG_UNDERLIER_CHAR,

		CAST (NULL AS VARCHAR2 (1 BYTE)) AS UPI_OTHR_LEG_NOTIONAL_CURR,

		CAST (NULL AS VARCHAR2 (1 BYTE)) AS UPI_OTHR_REF_RATE,

		CAST (NULL AS VARCHAR2 (1 BYTE)) AS UPI_OTHR_SUB_PRODUCT,

		CAST (NULL AS VARCHAR2 (1 BYTE)) AS UPI_OTHER_UNDERLIER_CHAR,

		CAST (NULL AS VARCHAR2 (1 BYTE)) AS UPI_PLACE_SETTLEMENT,

		CAST (NULL AS VARCHAR2 (1 BYTE)) AS UPI_REF_RATE,

		CAST (NULL AS VARCHAR2 (1 BYTE)) AS UPI_REF_RATE_TRM_UNT,

		CAST (NULL AS VARCHAR2 (1 BYTE)) AS UPI_REF_RATE_TRM_VAL,

		CASE
			WHEN DMX.THD_GROUP IN ('TRS','RTRN') AND DMX.THD_PKG_TYPE = 'TRS on MBS' OR DMX.THD_CONTRCT_TYPOLOGY_VAL LIKE '%MUA%' THEN 'Total Return'
			WHEN DMX.THD_TRD_CLASS_SRC_NAME IN('IRD_IRS','IRD_CS') OR (DMX.THD_TRD_CLASS_SRC_NAME = 'CRD_CDS' AND DMX.THD_TYPOLOGY_DESC = 'Bespoke CDS') THEN 'Credit Default'
			ELSE NULL
		END AS UPI_RETURN_PAYOUT_TRIGGER,

		CAST (NULL AS VARCHAR2 (1 BYTE)) AS UPI_SETTLEMENT_CURR,

		CAST (NULL AS VARCHAR2 (1 BYTE)) AS UPI_SUB_PRODUCT,

		CASE
			WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_TRS' OR DMX.THD_TRD_CLASS_SRC_NAME LIKE 'IRD_RTRN%' THEN
				CASE
					WHEN DMX.THD_PKG_NAME = 'TRS on MBS' OR DMX.THD_CONTRCT_TYPOLOGY_VAL LIKE '%MUA%' THEN 'Basket'
					ELSE NULL
				END
			WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'CRD_CDS' AND DMX.THD_TYPOLOGY_DESC = 'Bespoke CDS' THEN 'Single'
			WHEN DMX.THD_TRD_CLASS_SRC_NAME IN('IRD_IRS','IRD_CS') THEN
                CASE
                    WHEN NVL(DMX.TRP_CREDIT_BSK_NATURE_NEAR,DMX.TRP_CREDIT_BSK_NATURE_FAR) = 'Index' THEN 'Single'
                    WHEN TRIM(NVL(DMX.TRP_CREDIT_BSK_NATURE_NEAR,DMX.TRP_CREDIT_BSK_NATURE_FAR)) IS NOT NULL THEN 'Basket'
                    ELSE 'Single'
                END
			ELSE NULL
		END AS UPI_UNDERLIER_CHAR,

		sub_undrlng_asset_type.UPI_UNDRLNG_ASSET_TYPE AS UPI_UNDRLNG_ASSET_TYPE,

		sub_undrlng_crd_indx.UPI_UNDRLNG_CRD_INDX_SERIES AS UPI_UNDRLNG_CRD_INDX_SERIES,

		sub_undrlng_crd_indx.UPI_UNDRLNG_CRD_INDX_VERSION AS UPI_UNDRLNG_CRD_INDX_VERSION,

		sub_undrlng_instr.UPI_UNDRLNG_INSTR_INDX AS UPI_UNDRLNG_INSTR_INDX,

		CAST (NULL AS VARCHAR2 (1 BYTE)) AS UPI_UNDRLNG_INSTR_INDX_PROP,

		sub_undrlng_instr_term.UPI_UNDRLNG_INSTR_TERM_UNT AS UPI_UNDRLNG_INSTR_TERM_UNT,

		sub_undrlng_instr_term.UPI_UNDRLNG_INSTR_TERM_VAL AS UPI_UNDRLNG_INSTR_TERM_VAL,

		sub_undrlng_instr.UPI_UNDRLNG_INSTR_ISIN AS UPI_UNDRLNG_INSTR_ISIN,

		sub_undrlng_instr.UPI_UNDRLNG_INSTR_LEI AS UPI_UNDRLNG_INSTR_LEI,

		CAST (NULL AS VARCHAR2 (1 BYTE)) AS UPI_UNDRLNG_INSTR_UPI,

		sub_undrlng_issr.UPI_UNDRLNG_ISSUER_TYPE AS UPI_UNDRLNG_ISSUER_TYPE,

		CAST (NULL AS VARCHAR2 (1 BYTE))AS UPI_VALUATION_METHOD_TRIGGER,

		CAST (NULL AS VARCHAR2 (1 BYTE)) AS UPI_LAST_UPDATE_DATE_TIME,

		CAST (NULL AS VARCHAR2 (1 BYTE)) AS UPI_STATUS,

		CAST (NULL AS VARCHAR2 (1 BYTE)) AS UPI_STATUS_REASON,

		CASE
			WHEN sub_delivery_type.UPI_DELIVERY_TYPE = 'CASH' THEN 'Cash'
			WHEN sub_delivery_type.UPI_DELIVERY_TYPE = 'PHYS' THEN 'Physical'
			WHEN sub_delivery_type.UPI_DELIVERY_TYPE = 'OPTL' THEN 'Auction'
			ELSE NULL
		END AS UPI_CFI_DELIVERY_TYPE,

		CAST (NULL AS VARCHAR2 (1 BYTE)) AS UPI_CFI_OPTION_STYLE_TYPE,

		DMX.THD_CFI_INSTR_ID AS UPI_CLASSIFICATION_TYPE,

		CAST (NULL AS VARCHAR2 (1 BYTE)) AS UPI_SHORT_NAME,

		CAST (NULL AS VARCHAR2 (1 BYTE)) AS UPI_SINGLE_MULTI_CURR,

		CAST (NULL AS VARCHAR2 (1 BYTE)) AS UPI_UNDERLIER_NAME,

		CAST (NULL AS VARCHAR2 (1 BYTE)) AS UPI_FURTHER_GROUPING,

		DMX.THD_DSB_UPI AS UPI_DSB_UPI,

        CASE
            WHEN INSTR(sub_oth_fields.OTH_PAYMENT_PAYER_TYPE,',',1,18) = 0 THEN sub_oth_fields.OTH_PAYMENT_PAYER_TYPE
            ELSE SUBSTR(sub_oth_fields.OTH_PAYMENT_PAYER_TYPE,1,INSTR(sub_oth_fields.OTH_PAYMENT_PAYER_TYPE,',',1,18)-1)
        END AS OTH_PAYMENT_PAYER_TYPE,

        CASE
            WHEN INSTR(sub_oth_fields.OTH_PAYMENT_RECEIVER_TYPE,',',1,18) = 0 THEN sub_oth_fields.OTH_PAYMENT_RECEIVER_TYPE
            ELSE SUBSTR(sub_oth_fields.OTH_PAYMENT_RECEIVER_TYPE,1,INSTR(sub_oth_fields.OTH_PAYMENT_RECEIVER_TYPE,',',1,18)-1)
        END AS OTH_PAYMENT_RECEIVER_TYPE,
		CASE
			WHEN sub_instrument.UPI_INSTRUMENT_TYPE = 'Swap' AND sub_product.UPI_PRODUCT IN ('Corporate', 'Loan') THEN UPI_SWP_CORP.UPI_UNIQUE_PRD_ID
			WHEN sub_instrument.UPI_INSTRUMENT_TYPE = 'Swap' AND sub_product.UPI_PRODUCT = 'Sovereign' THEN UPI_SWP_SOV.UPI_UNIQUE_PRD_ID
			WHEN sub_instrument.UPI_INSTRUMENT_TYPE = 'Swap' AND sub_product.UPI_PRODUCT = 'Municipal' THEN UPI_SWP_MUNI.UPI_UNIQUE_PRD_ID
			WHEN sub_instrument.UPI_INSTRUMENT_TYPE = 'Swap' AND sub_product.UPI_PRODUCT = 'Loan' THEN UPI_SWP_LOAN.UPI_UNIQUE_PRD_ID
			WHEN sub_instrument.UPI_INSTRUMENT_TYPE = 'Swap' AND sub_product.UPI_PRODUCT = 'Index' THEN UPI_SWP_IDX.UPI_UNIQUE_PRD_ID
			WHEN sub_instrument.UPI_INSTRUMENT_TYPE = 'Swap' AND sub_product.UPI_PRODUCT = 'Total_Return_Swap' THEN UPI_SWP_TRS.UPI_UNIQUE_PRD_ID
			WHEN sub_instrument.UPI_INSTRUMENT_TYPE = 'Option' AND sub_product.UPI_PRODUCT = 'Single_Name_Swaption' THEN UPI_OPT_SNS.UPI_UNIQUE_PRD_ID
			WHEN sub_instrument.UPI_INSTRUMENT_TYPE = 'Option' AND sub_product.UPI_PRODUCT = 'Index_Swaption' THEN UPI_OPT_IDXS.UPI_UNIQUE_PRD_ID
			WHEN sub_instrument.UPI_INSTRUMENT_TYPE = 'Swap' AND sub_product.UPI_PRODUCT = 'Non_Standard' THEN UPI_SWP_NSTD.UPI_UNIQUE_PRD_ID
			ELSE NULL
		END AS UNIQUE_PRODUCT_IDENTIFIER,

        --<GH_Rewrite_Work>
        DMX.LEVEL_RPT,
        DMX.TP2_IND_PROVINCE,
        --</GH_Rewrite_Work>

    --!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!
    -- <Eric Change Canada Rewrite>
    --!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!

        CAST (NULL AS VARCHAR2 (1 BYTE)) AS EFFECTI_DATE_STRIKE,
        CAST (NULL AS VARCHAR2 (1 BYTE)) AS END_NOTIONAL_STRIKE,
        CAST (NULL AS VARCHAR2 (1 BYTE)) AS STRIKE_SCHEDULE,

        CASE
           WHEN DMX.THD_TRD_CLASS_SRC_NAME IN ('IRD_TRS','IRD_RTRN_SWAP') AND DMX.CUSTOM_BSK_IND = 'True'
           THEN DMX.REPORTING_PARTY_LEI||DMX.UTI
           ELSE NULL
        END AS CUSTOM_BSK_CODE,

        CASE
           WHEN DMX.CUSTOM_BSK_IND = 'True' AND DMX.THD_PKG_TYPE = 'TRS on MBS' THEN
              CASE
                 --WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_RTRN_SWAP' THEN TO_CLOB(DMX.LIST_ISIN_BSK_CONST_INSTRUMENTS) -- rendu en commentaire dans les specs ?!?!?
                 WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_TRS' THEN DMX.LST_BSK_CON_ID_TRSBOND
                 ELSE NULL
              END
           ELSE NULL
        END AS  CUSTOM_BSK_CONST_ID,

        CASE
           WHEN DMX.CUSTOM_BSK_IND = 'True' AND DMX.THD_PKG_TYPE = 'TRS on MBS' THEN
              CASE
                 --WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_RTRN_SWAP' THEN TO_CLOB(DMX.LIST_ISIN_BSK_CONST_ISSUERNAMES_SOURCE) -- rendu en commentaire dans les specs ?!?!?
                 WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_TRS'  THEN DMX.LST_BSK_CON_ID_SRC_TRSBOND
                 ELSE NULL
              END
           ELSE NULL
        END AS  CUSTOM_BSK_CONST_ID_SRC,

        CASE
           WHEN DMX.CUSTOM_BSK_IND = 'True' AND DMX.THD_PKG_TYPE = 'TRS on MBS' THEN
              CASE
                 --WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_RTRN_SWAP' THEN TO_CLOB(DMX.LIST_REMAIN_CAP_AMT_NEAR_NON_ZERO_BSK_CONST_NO_DISTINCT) -- rendu en commentaire dans les specs ?!?!?
                 WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_TRS' THEN DMX.LIST_BSK_CON_NB_UNIT_TRSBOND
                 ELSE NULL
              END
           ELSE NULL
        END AS  CUSTOM_BSK_CONST_NB_UNIT,

        CASE
           WHEN DMX.CUSTOM_BSK_IND = 'True' AND DMX.THD_PKG_TYPE = 'TRS on MBS' THEN
              CASE
                 --WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_RTRN_SWAP' THEN TO_CLOB(DMX.LIST_BSK_CONST_UNIT_MEAS) -- rendu en commentaire dans les specs ?!?!?
                 WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_TRS' THEN DMX.LIST_BSK_CON_UNIT_MEAS_TRSBOND
                 ELSE NULL
              END
           ELSE NULL
        END AS  CUSTOM_BSK_CONST_UNIT_MEAS,

		CAST (NULL AS VARCHAR2 (1 BYTE)) AS UNDERLIER_ID_OTHR_LEG1,
		CAST (NULL AS VARCHAR2 (1 BYTE)) AS UNDERLIER_ID_OTHR_LEG2,
		CAST (NULL AS VARCHAR2 (1 BYTE)) AS UNDERLYING_PRICE_SRC_LEG1,
		CAST (NULL AS VARCHAR2 (1 BYTE)) AS UNDERLYING_PRICE_SRC_LEG2,
		CAST (NULL AS VARCHAR2 (1 BYTE)) AS UNDERLIER_ID_OTHR_SRC_LEG1,
		CAST (NULL AS VARCHAR2 (1 BYTE)) AS UNDERLIER_ID_OTHR_SRC_LEG2,
        CAST (NULL AS VARCHAR2 (1 BYTE)) AS UNDERLYING_CRYPTO_LEG1,
        CAST (NULL AS VARCHAR2 (1 BYTE)) AS UNDERLYING_CRYPTO_LEG2,
        CAST (NULL AS VARCHAR2 (1 BYTE)) AS EFFECTI_DATE_NOTIONAL_QTY_LEG1,
        CAST (NULL AS VARCHAR2 (1 BYTE)) AS EFFECTI_DATE_NOTIONAL_QTY_LEG2,
        CAST (NULL AS VARCHAR2 (1 BYTE)) AS END_NOTIONAL_QTY_LEG1,
        CAST (NULL AS VARCHAR2 (1 BYTE)) AS END_NOTIONAL_QTY_LEG2,
        CAST (NULL AS VARCHAR2 (1 BYTE)) AS NOTIONAL_QTY_EFFECTI_DATE_LEG1,
        CAST (NULL AS VARCHAR2 (1 BYTE)) AS NOTIONAL_QTY_EFFECTI_DATE_LEG2,
        CAST (NULL AS VARCHAR2 (1 BYTE)) AS EFFECTI_DATE_PRICE,
        CAST (NULL AS VARCHAR2 (1 BYTE)) AS END_NOTIONAL_PRICE,
        CAST (NULL AS VARCHAR2 (1 BYTE)) AS PRICE_SCHEDULE,
        CAST (NULL AS VARCHAR2 (1 BYTE)) AS UNDERLYING_ASSET_PLTF_LEG1,
        CAST (NULL AS VARCHAR2 (1 BYTE)) AS UNDERLYING_ASSET_PLTF_LEG2

    --!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!
    -- </Eric Change Canada Rewrite>
    --!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!



    FROM
        DS_MUREX DMX
        LEFT JOIN BASIS_CONV_MAP BCM_CRD ON DMX.TRC_BASIS_CONV = BCM_CRD.INVAL
		LEFT JOIN BASIS_CONV_MAP BCM_NEAR ON DMX.TRP_BASIS_CONV_NEAR = BCM_NEAR.INVAL
		LEFT JOIN BASIS_CONV_MAP BCM_FAR ON DMX.TRP_BASIS_CONV_FAR = BCM_FAR.INVAL
		LEFT JOIN BASIS_CONV_MAP BCM_MULTI_NEAR ON DMX.MLT_DAY_COUNT_CONV_DESC_SIDE1 = BCM_MULTI_NEAR.INVAL
		LEFT JOIN BASIS_CONV_MAP BCM_MULTI_FAR ON DMX.MLT_DAY_COUNT_CONV_DESC_SIDE2 = BCM_MULTI_FAR.INVAL
		LEFT JOIN SETTLEMENT_CONV_MAP SCM ON DMX.THD_CRD_SETTLEMENT_TYPE = SCM.INVAL
		--<GH_Rewrite_Work>
		CROSS APPLY
		(
            SELECT
               CASE
                  WHEN (
                          ( DMX.THD_FGT_GRP IN('TRS','RTRN') AND DMX.UPI LIKE 'Credit%' )
                            OR
                          ( DMX.THD_TRD_CLASS_SRC_NAME IN ('IRD_IRS','IRD_CS') AND DMX.THD_CONTRCT_TYPOLOGY_VAL LIKE 'CR Link%')
                       )
                  THEN
                     CASE

                        WHEN DMX.THD_ORIG_EFFECT_DATE IS NOT NULL
                        THEN DMX.THD_ORIG_EFFECT_DATE

                        WHEN DMX.THD_FGT_GRP IN ('TRS','IRS', 'CS')
                        THEN DMX.THD_UNADJST_LEG1_START_DATE

                        WHEN DMX.THD_FGT_GRP IN ('RTRN')
                        THEN DMX.THD_UNADJST_LEG2_START_DATE
                     END

                  WHEN DMX.THD_TRD_CLASS_SRC_NAME LIKE 'CRD%'
                  THEN DMX.THD_UNADJST_LEG1_START_DATE
               END AS EFFECTIVE_DATE
            FROM DUAL
        ) sub_effective_date

-----------------------------------------------------
-- Eric: Changement sur le MASTER_AGREEMENT_TYPE (sub_agreement_type).
--       POurrait  tre boug  comme COMMUN mais compte tenu des discussion, laiss  ici pour le moment
-----------------------------------------------------

--		CROSS APPLY
--		(
--            SELECT
--                CASE
--                    WHEN NVL(DMX.SEF_DCM_ANONYM,' ') != 'true' THEN
--                        CASE
--                            WHEN NVL(DMX.MLG_CONTRACT_DATE,TO_DATE('9999-12-31','YYYY-MM-DD')) <= NVL(sub_effective_date.EFFECTIVE_DATE,TO_DATE('1900-01-01','YYYY-MM-DD')) THEN 'ISDA'
--                            ELSE 'BIAG'
--                        END
--                    ELSE NULL
--                END AS MASTER_AGREEMENT_TYPE
--            FROM DUAL
--		) sub_agreement_type
--       --</GH_Rewrite_Work>

		CROSS APPLY
		(
            SELECT
                CASE
                    WHEN NVL(DMX.SEF_DCM_ANONYM,' ') != 'true'
                    THEN DECODE(DMX.MLG_SID, NULL, 'BIAG', 'ISDA')
                    ELSE NULL
                END AS MASTER_AGREEMENT_TYPE
            FROM DUAL
		) sub_agreement_type

        CROSS APPLY
        (
            --<GH_Rewrite_Work>
            --champs splitt s CFTC_CSA
            SELECT
                FIXED_RATE1_TMP AS FIXED_RATE1_CFTC,
                FIXED_RATE1_TMP AS FIXED_RATE1_CSA,
                FIXED_RATE2_TMP AS FIXED_RATE2_CFTC,
                FIXED_RATE2_TMP AS FIXED_RATE2_CSA
            FROM
            (
                SELECT
                    CASE
                        WHEN DMX.THD_TRD_CLASS_SRC_NAME IN('CRD_CDS','CRD_CRDI')
                             AND NVL(DMX.THD_PKG_NAME,' ') != 'Risk Participation Agreement'
                             AND DMX.TRC_FIX_FLOAT_RATE_IND = 'F'
                        THEN DMX.THD_CONTR_PX_RATE_VAL/100

                        WHEN DMX.THD_TRD_CLASS_SRC_NAME IN('IRD_CS','IRD_IRS')
                             AND DMX.THD_CONTRCT_TYPOLOGY_VAL LIKE 'CR Link%'
                             AND NVL(DMX.THD_POST_PRICED_SWAP_IND_FLG,' ') != 'Y'
                             AND DMX.TRP_FIX_FLOAT_RATE_IND_NEAR='F'

                        THEN DMX.MAX_FIX_MARGIN_RATE_NEAR_INT_IN_PERIOD/100
                        ELSE NULL
                    END AS FIXED_RATE1_TMP,

                    CASE
                        WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_TRS' AND DMX.THD_FIX_FLOAT_RATE_IND = 'F' THEN DMX.THD_PRICE_AMT -- d j  divis  par 100
                        WHEN DMX.THD_FGT_GRP = 'RTRN' AND DMX.TRP_FIX_FLOAT_RATE_IND_FAR = 'F' THEN DMX.TRP_PX_RATE_VAL_FAR / 100

                        WHEN DMX.THD_TRD_CLASS_SRC_NAME IN('IRD_CS','IRD_IRS')
                             AND DMX.THD_CONTRCT_TYPOLOGY_VAL LIKE 'CR Link%'
                             AND NVL(DMX.THD_POST_PRICED_SWAP_IND_FLG,' ') != 'Y'
                             AND DMX.TRP_FIX_FLOAT_RATE_IND_FAR = 'F'

                        THEN DMX.MAX_FIX_MARGIN_RATE_FAR_INT_IN_PERIOD/100

                        ELSE NULL
                    END AS FIXED_RATE2_TMP
                FROM DUAL
            ) foo
            --</GH_Rewrite_Work>
        ) sub_fixed_rate
        CROSS APPLY
        (

            SELECT
                --<GH_Rewrite_Work>
                --champs splitt s CFTC_CSA
--                DECODE(sub_fixed_rate.FIXED_RATE1,NULL,SPREAD1_TMP,NULLIF(SPREAD1_TMP,0)) AS SPREAD1,
--                DECODE(sub_fixed_rate.FIXED_RATE2,NULL,SPREAD2_TMP,NULLIF(SPREAD2_TMP,0)) AS SPREAD2
                DECODE(sub_fixed_rate.FIXED_RATE1_CFTC,NULL,SPREAD1_TMP,NULLIF(SPREAD1_TMP,0)) AS SPREAD1_CFTC,
                DECODE(sub_fixed_rate.FIXED_RATE1_CSA,NULL,SPREAD1_TMP,NULLIF(SPREAD1_TMP,0)) AS SPREAD1_CSA,
                DECODE(sub_fixed_rate.FIXED_RATE2_CFTC,NULL,SPREAD2_TMP,NULLIF(SPREAD2_TMP,0)) AS SPREAD2_CFTC,
                DECODE(sub_fixed_rate.FIXED_RATE2_CSA,NULL,SPREAD2_TMP,NULLIF(SPREAD2_TMP,0)) AS SPREAD2_CSA
                --</GH_Rewrite_Work>
            FROM
            (
                SELECT
                    CASE
                        WHEN DMX.THD_FGT_GRP = 'TRS' AND UPI LIKE 'Credit%' AND DMX.TRP_FIX_FLOAT_RATE_IND_FAR = 'V' THEN (DMX.TRP_LEG_MARGIN_PX_RATE_VAL_FAR+NVL(DMX.MAX_FFL_INDEX_SPREAD_AMT_FAR,0)) / 100
                        WHEN DMX.THD_FGT_GRP = 'RTRN' AND UPI LIKE 'Credit%' AND DMX.TRP_FIX_FLOAT_RATE_IND_NEAR = 'V' THEN (DMX.TRP_LEG_MARGIN_PX_RATE_VAL_NEAR+NVL(DMX.MAX_FFL_INDEX_SPREAD_AMT_NEAR,0)) / 100
                        WHEN DMX.THD_TRD_CLASS_SRC_NAME IN('IRD_IRS','IRD_CS') AND DMX.TRP_FIX_FLOAT_RATE_IND_NEAR = 'V' THEN DECODE(DMX.IS_MULTIPHASE,'Y',DMX.MLT_MRGN_SPREAD_SIDE1,NVL(DMX.TRP_LEG_MARGIN_PX_RATE_VAL_NEAR,0) + NVL(DMX.MAX_FFL_INDEX_SPREAD_AMT_NEAR,0)) / 100
                        ELSE NULL
                    END AS SPREAD1_TMP,
                    CASE
                        WHEN DMX.THD_FGT_GRP = 'TRS' AND UPI LIKE 'Credit%' AND DMX.TRP_FIX_FLOAT_RATE_IND_NEAR = 'V' THEN (DMX.TRP_LEG_MARGIN_PX_RATE_VAL_NEAR+NVL(DMX.MAX_FFL_INDEX_SPREAD_AMT_NEAR,0)) / 100
                        WHEN DMX.THD_FGT_GRP = 'RTRN' AND UPI LIKE 'Credit%' AND DMX.TRP_FIX_FLOAT_RATE_IND_FAR = 'V' THEN (DMX.TRP_LEG_MARGIN_PX_RATE_VAL_FAR+NVL(DMX.MAX_FFL_INDEX_SPREAD_AMT_FAR,0)) / 100
                        WHEN DMX.THD_TRD_CLASS_SRC_NAME IN('IRD_IRS','IRD_CS') AND DMX.TRP_FIX_FLOAT_RATE_IND_FAR = 'V' THEN DECODE(DMX.IS_MULTIPHASE,'Y',DMX.MLT_MRGN_SPREAD_SIDE2,NVL(DMX.TRP_LEG_MARGIN_PX_RATE_VAL_FAR,0) + NVL(DMX.MAX_FFL_INDEX_SPREAD_AMT_FAR,0)) / 100
                        ELSE NULL
                    END AS SPREAD2_TMP
                FROM DUAL
            ) foo
        ) sub_spread
		CROSS APPLY
        (
            SELECT
                CASE
                    WHEN (DMX.THD_FAMILY = 'CRD' AND DMX.THD_GROUP IN ('CDS','CRDI','RTRS')) OR (DMX.THD_FAMILY = 'IRD' AND DMX.THD_GROUP IN ('TRS','RTRN','IRS','CS')) THEN 'Swap'
                    WHEN DMX.THD_FAMILY = 'CRD' AND DMX.THD_GROUP IN ('CRDIO','OCDO','OCDS','OASWP','OBDS') THEN 'Option'
                END AS UPI_INSTRUMENT_TYPE
            FROM DUAL
        ) sub_instrument
        CROSS APPLY
        (
            SELECT
                CASE
                    WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'CRD_CRDI' THEN 'Index'
                    WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_TRS' OR DMX.THD_TRD_CLASS_SRC_NAME LIKE 'IRD_RTRN%' THEN
                        CASE
                            WHEN DMX.THD_PKG_NAME = 'TRS on MBS' OR DMX.THD_CONTRCT_TYPOLOGY_VAL LIKE '%MUA%' THEN 'Non_Standard'
                            ELSE 'Total_Return_Swap'
                        END
                    WHEN DMX.THD_TRD_CLASS_SRC_NAME IN('IRD_IRS','IRD_CS') THEN	'Non_Standard'
                    WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'CRD_CDS' THEN
                        CASE
                            WHEN DMX.THD_TYPOLOGY_DESC = 'LCDS' THEN 'Loan'
                            WHEN DMX.THD_TYPOLOGY_DESC = 'Bespoke CDS' THEN 'Non_Standard'
                            WHEN DMX.RPY_REF_INDSTRY_GRP_ISSR LIKE '%Municipal%' THEN 'Municipal'
                            WHEN DMX.RPY_REF_INDSTRY_GRP_ISSR LIKE '%Sovereign%' THEN 'Sovereign'
                            ELSE 'Corporate'
                        END
                    ELSE NULL
                END AS UPI_PRODUCT
            FROM DUAL
        ) sub_product
		/*CROSS APPLY
        (
            SELECT
                CASE
					WHEN DMX.THD_GROUP IN ('RTRN','TRS') AND DMX.UPI LIKE 'Credit%' THEN 'Cash'
                    WHEN DMX.THD_TRD_CLASS_SRC_NAME LIKE 'CRD%' THEN SCM.OUTVAL
                    ELSE NULL
                END AS SETTLEMENT_TYPE
            FROM DUAL
        ) sub_settlement_type*/
		CROSS APPLY
		(
			SELECT
				CASE
					WHEN DMX.THD_GROUP = 'TRS' AND UPI LIKE 'Credit%' THEN 'CASH'
					WHEN DMX.THD_GROUP = 'RTRN' AND UPI LIKE 'Credit%' THEN DMX.THD_MIFID_56_CODE
					WHEN DMX.THD_FAMILY = 'CRD' THEN DECODE(DMX.THD_CRD_SETTLEMENT_TYPE,'Cash','CASH','Delivery','PHYS','Cash or delivery','OPTL','Auction','OPTL',NULL)
					WHEN DMX.THD_TRD_CLASS_SRC_NAME IN('IRD_IRS','IRD_CS') THEN DECODE(NVL(DMX.TRP_CREDIT_ISDA_VERSION_NEAR,DMX.TRP_CREDIT_ISDA_VERSION_FAR),'cash settle','CASH','Delivery','PHYS','Cash or delivery','OPTL','Auction','OPTL',NULL)
					ELSE NULL
				END AS UPI_DELIVERY_TYPE
			FROM DUAL
		) sub_delivery_type
		CROSS APPLY
		(
			SELECT
				CASE
					WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'CRD_CDS' THEN
						CASE
                            --<GH_Rewrite_Work>
							--WHEN DMX.THD_TYPOLOGY_DESC = 'LCDS' THEN DMX.RPY_LEI_NO_CPTY
							WHEN DMX.THD_TYPOLOGY_DESC = 'LCDS' THEN DMX.COUNTERPARTY_LEI
							--</GH_Rewrite_Work>
							WHEN DMX.THD_TYPOLOGY_DESC IN('NON Red - CDS','Bespoke CDS') OR DMX.THD_PKG_NAME = 'Risk Participation Agreement' THEN DMX.RPY_LEI_NO_UNDERLY_ISSUER
							ELSE NVL(DMX.RIN_ISIN_ID_INSTR,DMX.RIN_CUSIP_ID_INSTR)
						END
					WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'CRD_CRDI' THEN DMX.RIN_RED_CODE_ID_INSTR
					WHEN DMX.UPI LIKE 'Credit%' THEN
						CASE
							WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_TRS' THEN
								CASE
                                    --<GH_Rewrite_Work>
									--WHEN DMX.THD_MBS_SERIES_VAL LIKE '%MBS%' THEN DMX.TRP_LEG_MAIN_IDX_VAL_LEFT_UNDERSCORE_FAR || '_MBS_Series_ID' || DMX.THD_MBS_SERIES_VAL
									WHEN DMX.THD_PKG_TYPE = 'TRS on MBS' THEN DMX.TRP_LEG_MAIN_IDX_VAL_LEFT_UNDERSCORE_FAR || '_MBS_Series_ID' || DMX.THD_MBS_SERIES_VAL
									--</GH_Rewrite_Work>
									WHEN DMX.THD_SEC_GRP_VAL = 'Bond' THEN COALESCE(DMX.RIN_ISIN_ID_MAIN_IDX_LEFT_UNDERSCORE_FAR,DMX.RIN_CUSIP_ID_MAIN_IDX_LEFT_UNDERSCORE_FAR,RIN_BB_GLB_ID_MAIN_IDX_LEFT_UNDERSCORE_FAR)
									WHEN DMX.THD_SEC_GRP_VAL = 'Basket' THEN DMX.TRP_LEG_MAIN_IDX_VAL_FAR
									ELSE NULL
								END
							WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_RTRN_SWAP' THEN
								CASE
                                    --<GH_Rewrite_Work>
									--WHEN DMX.THD_MBS_SERIES_VAL LIKE '%MBS%' THEN DMX.THD_MBS_SERIES_VAL
									WHEN DMX.THD_PKG_TYPE = 'TRS on MBS' THEN DMX.TRP_LEG_MAIN_IDX_VAL_LEFT_UNDERSCORE_FAR || '_MBS_Series_ID' || DMX.THD_MBS_SERIES_VAL
									--</GH_Rewrite_Work>
									ELSE COALESCE(DMX.RIN_ISIN_ID_MAIN_IDX_LEFT_UNDERSCORE_NEAR,RIN_CUSIP_ID_MAIN_IDX_LEFT_UNDERSCORE_NEAR,RIN_BB_GLB_ID_MAIN_IDX_LEFT_UNDERSCORE_NEAR)
								END
							WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_RTRN_BSK' THEN DMX.LIST_ISIN_TICKER_UNDERLIER
							WHEN DMX.THD_TRD_CLASS_SRC_NAME IN('IRD_IRS','IRD_CS') THEN
                                CASE
                                    WHEN NVL(DMX.TRP_CREDIT_BSK_NATURE_NEAR,DMX.TRP_CREDIT_BSK_NATURE_FAR) = 'Index' THEN DMX.RIN_RED_CODE_ID_CRD_BSK_LBL
                                    WHEN TRIM(NVL(DMX.TRP_CREDIT_REF_ENTITY_NEAR,DMX.TRP_CREDIT_REF_ENTITY_FAR)) IS NOT NULL THEN COALESCE(DMX.RIN_ISIN_ID_CRD_REF_ENTITY,DMX.RIN_CUSIP_ID_CRD_REF_ENTITY,DMX.RPY_ISSUER_CRD_REF_ENTITY_LEI)
                                    ELSE NULL
                                END
							ELSE NULL
						END
					ELSE NULL
				END AS UNDERLIER_ID_LEG1,
				CASE
					WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'CRD_CDS' THEN
						CASE
							WHEN DMX.THD_TYPOLOGY_DESC = 'LCDS' THEN 'LEI'
							WHEN DMX.THD_TYPOLOGY_DESC = 'NON Red - CDS' OR DMX.THD_PKG_NAME = 'Risk Participation Agreement' THEN 'LEI'
							WHEN DMX.RIN_ISIN_ID_INSTR IS NOT NULL THEN 'ISIN'
							WHEN DMX.RIN_CUSIP_ID_INSTR IS NOT NULL THEN 'CUSIP'
							ELSE NULL
						END
					WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'CRD_CRDI' THEN 'REDID'
					WHEN DMX.UPI LIKE 'Credit%' THEN
						CASE
							WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_TRS' THEN
								CASE
									WHEN DMX.THD_PKG_NAME = 'TRS on MBS' THEN 'Basket'
									WHEN DMX.THD_SEC_GRP_VAL = 'Bond' THEN
										CASE
											WHEN DMX.RIN_ISIN_ID_MAIN_IDX_LEFT_UNDERSCORE_FAR IS NOT NULL THEN 'ISIN'
											WHEN DMX.RIN_CUSIP_ID_MAIN_IDX_LEFT_UNDERSCORE_FAR IS NOT NULL THEN 'CUSIP'
											WHEN DMX.RIN_BB_GLB_ID_MAIN_IDX_LEFT_UNDERSCORE_FAR IS NOT NULL THEN 'Bloomberg'
											ELSE NULL
										END
									ELSE NULL
								END
							WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_RTRN_SWAP' THEN
								CASE
									WHEN DMX.THD_PKG_NAME = 'TRS on MBS' THEN 'Basket'
									WHEN DMX.RIN_ISIN_ID_MAIN_IDX_LEFT_UNDERSCORE_NEAR IS NOT NULL THEN 'ISIN'
									WHEN DMX.RIN_CUSIP_ID_MAIN_IDX_LEFT_UNDERSCORE_NEAR IS NOT NULL THEN 'CUSIP'
									WHEN DMX.RIN_BB_GLB_ID_MAIN_IDX_LEFT_UNDERSCORE_NEAR IS NOT NULL THEN 'Bloomberg'
									ELSE NULL
								END
							WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_RTRN_BSK' THEN DMX.LIST_ISIN_TICKER_UNDERLIER_SOURCE
							WHEN DMX.THD_TRD_CLASS_SRC_NAME IN('IRD_IRS','IRD_CS') THEN
                                CASE
                                    WHEN NVL(DMX.TRP_CREDIT_BSK_NATURE_NEAR,DMX.TRP_CREDIT_BSK_NATURE_FAR) = 'Index' THEN 'REDID'
                                    WHEN TRIM(NVL(DMX.TRP_CREDIT_REF_ENTITY_NEAR,DMX.TRP_CREDIT_REF_ENTITY_FAR)) IS NOT NULL THEN
                                        CASE
                                            WHEN DMX.RIN_ISIN_ID_CRD_REF_ENTITY IS NOT NULL THEN 'ISIN'
                                            WHEN DMX.RIN_CUSIP_ID_CRD_REF_ENTITY IS NOT NULL THEN 'CUSIP'
                                            ELSE 'LEI'
                                        END
                                    ELSE NULL
                                END

							ELSE NULL
						END
					ELSE NULL
				END AS UNDERLYING_SOURCE_LEG1
			FROM DUAL
		) sub_underlier
		CROSS APPLY
		(
			SELECT
				CASE
					WHEN DMX.THD_TRD_CLASS_SRC_NAME IN ('IRD_TRS','IRD_RTRN_BSK') THEN NULL
					WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'CRD_CDS' THEN
						CASE
							WHEN DMX.THD_TYPOLOGY_DESC = 'LCDS' THEN 'Corporate'
							WHEN DMX.THD_PKG_TYPE = 'Risk Participation Agreement' THEN NULL
							WHEN NVL(DMX.THD_TYPOLOGY_DESC,' ') NOT IN ('LCDS','Bespoke CDS') THEN REGEXP_SUBSTR(DMX.THD_UN_PRODUCT_ID_VAL,'[^:]+',1,4)
							ELSE NULL
						END
                    WHEN DMX.THD_TRD_CLASS_SRC_NAME IN('IRD_IRS','IRD_CS') THEN DECODE(TRIM(NVL(DMX.TRP_CREDIT_BSK_LABEL_NEAR,DMX.TRP_CREDIT_BSK_LABEL_FAR)),NULL,DMX.RIN_CDS_ISDA_TRANSACTION_TYPE_CRD_REF_ENTITY,NULL) --it ration #453278593278945327894532678954367892 de BC1536, previously DMX.RIN_CDS_ISDA_TRANSACTION_TYPE_CRD_REF_OBL
					ELSE NULL
				END AS UPI_CONTRACT_SPEC
			FROM DUAL
		) sub_contract_spec
		CROSS APPLY
		(
			SELECT
				CASE
					WHEN DMX.THD_PKG_NAME = 'TRS on MBS' OR DMX.THD_CONTRCT_TYPOLOGY_VAL LIKE '%MUA%' THEN NULL
					WHEN DMX.THD_TRD_CLASS_SRC_NAME IN('CRD_CDS','IRD_IRS','IRD_CS') THEN
						CASE
							WHEN COALESCE(DMX.TRC_PROTECT_RSK_SECTN_VAL,DMX.TRP_CREDIT_SENIORITY_NEAR,DMX.TRP_CREDIT_SENIORITY_FAR) = 'Asset Backed' THEN 'MZZD'
							WHEN COALESCE(DMX.TRC_PROTECT_RSK_SECTN_VAL,DMX.TRP_CREDIT_SENIORITY_NEAR,DMX.TRP_CREDIT_SENIORITY_FAR) IN ('Senior Non Pref','Senior Secured','Senior Unsecure','Senior Unsecured','Unsubordinated') THEN 'SNDB'
							WHEN COALESCE(DMX.TRC_PROTECT_RSK_SECTN_VAL,DMX.TRP_CREDIT_SENIORITY_NEAR,DMX.TRP_CREDIT_SENIORITY_FAR) = 'Subordinated' THEN 'SBOD'
						END
					WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_TRS' THEN DMX.RIN_ESMA_SENIORITY_MAIN_IDX_LEFT_UNDERSCORE_FAR
					WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_RTRN_SWAP' THEN DMX.RIN_ESMA_SENIORITY_MAIN_IDX_LEFT_UNDERSCORE_NEAR
					WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_RTRN_BSK' THEN DMX.LIST_UPI_DEBT_SENIORITY
					ELSE NULL
				END AS UPI_DEBT_SENIORITY
			FROM DUAL
		) sub_debt_seniority
		CROSS APPLY
		(
			SELECT
				CASE
					WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'CRD_CDS' AND NVL(DMX.THD_TYPOLOGY_DESC, ' ') NOT IN ('NON Red - CDS','LCDS','Bespoke CDS') THEN sub_underlier.UNDERLIER_ID_LEG1
					WHEN DMX.THD_TRD_CLASS_SRC_NAME IN('IRD_IRS','IRD_CS') AND sub_underlier.UNDERLYING_SOURCE_LEG1 = 'ISIN' THEN sub_underlier.UNDERLIER_ID_LEG1
					WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_TRS' OR DMX.THD_TRD_CLASS_SRC_NAME LIKE 'IRD_RTRN%' THEN
						CASE
							WHEN NVL(DMX.THD_PKG_TYPE, ' ') != 'TRS on MBS' AND sub_underlier.UNDERLYING_SOURCE_LEG1 = 'ISIN' AND DMX.THD_CONTRCT_TYPOLOGY_VAL NOT LIKE '%MUA%' THEN sub_underlier.UNDERLIER_ID_LEG1
							ELSE NULL
						END
					ELSE NULL
				END AS UPI_UNDRLNG_INSTR_ISIN,
				CASE
					WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'CRD_CDS' AND DMX.THD_TYPOLOGY_DESC IN ('NON Red - CDS','LCDS','Bespoke CDS') THEN sub_underlier.UNDERLIER_ID_LEG1
					WHEN DMX.THD_TRD_CLASS_SRC_NAME IN('IRD_IRS','IRD_CS') AND sub_underlier.UNDERLYING_SOURCE_LEG1 = 'LEI' THEN sub_underlier.UNDERLIER_ID_LEG1
					ELSE NULL
				END AS UPI_UNDRLNG_INSTR_LEI,
				CASE
					WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'CRD_CRDI' THEN DMX.RIN_CDS_IDX_SUB_FAMILY_INSTR
					WHEN DMX.THD_TRD_CLASS_SRC_NAME IN('IRD_IRS','IRD_CS') AND TRIM(NVL(DMX.TRP_CREDIT_BSK_NATURE_NEAR,DMX.TRP_CREDIT_BSK_NATURE_FAR)) IS NOT NULL THEN DMX.RIN_CDS_IDX_SUB_FAMILY_CRD_BSK_LBL
					ELSE NULL
				END AS UPI_UNDRLNG_INSTR_INDX
			FROM DUAL
		) sub_undrlng_instr
		CROSS APPLY
		(
			SELECT
				CASE
					WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'CRD_CRDI' THEN DMX.RIN_BND_SERIES_VAL_INSTR
					WHEN DMX.THD_TRD_CLASS_SRC_NAME IN('IRD_IRS','IRD_CS') AND TRIM(NVL(DMX.TRP_CREDIT_BSK_NATURE_NEAR,DMX.TRP_CREDIT_BSK_NATURE_FAR)) IS NOT NULL THEN DMX.RIN_BND_SERIES_VAL_CRD_BSK_LBL
					ELSE NULL
				END AS UPI_UNDRLNG_CRD_INDX_SERIES,
				CASE
					WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'CRD_CRDI' THEN DMX.RIN_ISSUE_VERSION_INSTR
					WHEN DMX.THD_TRD_CLASS_SRC_NAME IN('IRD_IRS','IRD_CS') AND TRIM(NVL(DMX.TRP_CREDIT_BSK_NATURE_NEAR,DMX.TRP_CREDIT_BSK_NATURE_FAR)) IS NOT NULL THEN DMX.RIN_ISSUE_VERSION_CRD_BSK_LBL
					ELSE NULL
				END AS UPI_UNDRLNG_CRD_INDX_VERSION
			FROM DUAL
		) sub_undrlng_crd_indx
		CROSS APPLY
		(
			SELECT
				CASE
					WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'CRD_CRDI' THEN DMX.RIN_CFI_UNDERL_ISSUER_TYPE_INSTR
					WHEN DMX.THD_TRD_CLASS_SRC_NAME IN('IRD_IRS','IRD_CS') THEN DECODE(TRIM(NVL(DMX.TRP_CREDIT_BSK_LABEL_NEAR,DMX.TRP_CREDIT_BSK_LABEL_FAR)),NULL,RIN_CFI_UNDERL_ISSUER_TYPE_CRD_REF_ENTITY,RIN_CFI_UNDERL_ISSUER_TYPE_CRD_BSK_LBL) --DMX.RIN_CFI_UNDERL_ISSUER_TYPE_CRD_REF_ENTITY --it ration #453278593278945327894532678954367892 de BC1536, previously DMX.RIN_CFI_UNDERL_ISSUER_TYPE_CRD_REF_OBL
					WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'CRD_CDS' THEN
						CASE
							WHEN DMX.THD_TYPOLOGY_DESC = 'Bespoke CDS' THEN
								CASE
									WHEN DMX.RPY_REF_INDSTRY_GRP_ISSR LIKE '%Municipal%' THEN 'Municipal'
									WHEN DMX.RPY_REF_INDSTRY_GRP_ISSR LIKE '%Sovereign%' THEN 'Sovereign'
									ELSE NULL
								END
							ELSE 'Corporate'
						END
					WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_TRS' OR DMX.THD_TRD_CLASS_SRC_NAME LIKE 'IRD_RTRN%' THEN 'Corporate'
					ELSE NULL
				END  AS UPI_UNDRLNG_ISSUER_TYPE
			FROM DUAL
		) sub_undrlng_issr
		CROSS APPLY
		(
			SELECT
                CASE
                    WHEN TENOR_TMP LIKE '%Y' THEN 'YEAR'
                    WHEN TENOR_TMP LIKE '%M' THEN 'MNTH'
                    WHEN TENOR_TMP LIKE '%W' THEN 'WEEK'
                    WHEN TENOR_TMP LIKE '%D' THEN 'DAYS'
                    ELSE NULL
                END AS UPI_UNDRLNG_INSTR_TERM_UNT,
                REGEXP_SUBSTR(TENOR_TMP, '^\d+') AS UPI_UNDRLNG_INSTR_TERM_VAL
            FROM
            (
                SELECT
                    CASE
                        WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'CRD_CRDI' THEN DMX.RIN_CDS_TENOR_INSTR
                        WHEN DMX.THD_TRD_CLASS_SRC_NAME IN('IRD_IRS','IRD_CS') AND TRIM(NVL(DMX.TRP_CREDIT_BSK_NATURE_NEAR,DMX.TRP_CREDIT_BSK_NATURE_FAR)) IS NOT NULL THEN DMX.RIN_CDS_TENOR_CRD_BSK_LBL
                        ELSE NULL
                    END AS TENOR_TMP
                FROM DUAL
            )
		) sub_undrlng_instr_term
		CROSS APPLY
		(
			SELECT
				CASE
					WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_TRS' OR DMX.THD_TRD_CLASS_SRC_NAME LIKE 'IRD_RTRN%' THEN
						CASE
							WHEN DMX.THD_PKG_TYPE = 'TRS on MBS' OR DMX.THD_CONTRCT_TYPOLOGY_VAL LIKE '%MUA%' THEN 'Total Return'
							ELSE NULL
						END
					WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'CRD_CDS' AND DMX.THD_TYPOLOGY_DESC = 'Bespoke CDS' THEN 'Credit Default'
					ELSE NULL
				END AS UPI_RETURN_PAYOUT_TRIGGER
			FROM DUAL
		) sub_return_payout_trigger
		CROSS APPLY
		(
			SELECT
				CASE
					WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'CRD_CRDI' THEN 'Index'
					WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'CRD_CDS' AND DMX.THD_TYPOLOGY_DESC = 'LCDS' THEN 'Other'
					WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'CRD_CDS' THEN 'Single Name'
					WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_TRS' OR DMX.THD_TRD_CLASS_SRC_NAME LIKE 'IRD_RTRN%' THEN
						CASE
							WHEN DMX.THD_PKG_TYPE = 'TRS on MBS' THEN 'Basket'
							WHEN DMX.THD_CONTRCT_TYPOLOGY_VAL LIKE '%MUA%' THEN 'Other'
							ELSE 'Single Name'
						END
					WHEN DMX.THD_TRD_CLASS_SRC_NAME IN('IRD_IRS','IRD_CS') THEN
                        CASE
                            WHEN TRIM(NVL(DMX.TRP_CREDIT_BSK_NATURE_NEAR,DMX.TRP_CREDIT_BSK_NATURE_FAR)) IS NOT NULL THEN 'Index'
                            ELSE 'Single Name'
                        END
					ELSE NULL
				END AS UPI_UNDRLNG_ASSET_TYPE
			FROM DUAL
		) sub_undrlng_asset_type
		CROSS APPLY
		(
            SELECT
                TRIM(',' FROM
                (
                    CASE
                        WHEN DMX.THD_TRD_CLASS_SRC_NAME IN('CRD_CDS','CRD_CRDI','IRD_IRS','IRD_CS') AND NVL(DMX.THD_TYPOLOGY_DESC,' ') != 'Bespoke CDS' AND NVL(DMX.THD_INITIALPAYMENT_AMT, 0) != 0 THEN 'UFRO'
                        ELSE NULL
                    END
                    ||
                    CASE
                        WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_RTRN_SWAP' AND DMX.LIST_UFRO_RPL_P IS NOT NULL THEN ',' || DMX.LIST_UFRO_RPL_P
                        ELSE NULL
                    END
                    ||
                    CASE
                        WHEN DMX.THD_TYPOLOGY_DESC = 'Bespoke CDS' AND DMX.LIST_UFRO_LNBR_CDS IS NOT NULL THEN ',' || DMX.LIST_UFRO_LNBR_CDS
                        ELSE NULL
                    END
                    ||
                    CASE
                        WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_CS' AND DMX.LIST_PEXH_PRI IS NOT NULL THEN ',' || DMX.LIST_PEXH_PRI
                        ELSE NULL
                    END
                    ||
                    CASE
                        WHEN (DMX.THD_TRD_CLASS_SRC_NAME LIKE 'CRD%' OR (DMX.THD_FGT_GRP IN('RTRN','TRS') AND DMX.UPI LIKE 'Credit%')) AND DMX.LIST_UWIN_MOP IS NOT NULL THEN ',' || DMX.LIST_UWIN_MOP
                        ELSE NULL
                    END
                )) AS OTH_PAYMENT_TYPE,

                TRIM(',' FROM (
                    CASE
                        WHEN DMX.THD_TRD_CLASS_SRC_NAME IN('CRD_CDS','CRD_CRDI','IRD_IRS','IRD_CS') AND NVL(DMX.THD_TYPOLOGY_DESC,' ') != 'Bespoke CDS' AND NVL(DMX.THD_INITIALPAYMENT_AMT, 0) != 0 THEN RTRIM(TO_CHAR(FMT_ELT.FLEXIBLE_ROUND(ABS(DMX.THD_INITIALPAYMENT_AMT),2,'HALF_DOWN'),'FM999999999999999999999999999999990.99'),'.')   --RTRIM(TO_CHAR(ABS(DMX.THD_INITIALPAYMENT_AMT), 'FM99999999999990.999999999999'), '.')
                        ELSE NULL
                    END
                    ||
                    CASE
                        WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_RTRN_SWAP' AND DMX.LIST_FFL_PYMT_AMT_RPL_P IS NOT NULL THEN ',' || DMX.LIST_FFL_PYMT_AMT_RPL_P
                        ELSE NULL
                    END
                    ||
                    CASE
                        WHEN DMX.THD_TYPOLOGY_DESC = 'Bespoke CDS' AND DMX.LIST_FFL_PYMT_LNBR_CDS IS NOT NULL THEN ',' || DMX.LIST_FFL_PYMT_LNBR_CDS
                        ELSE NULL
                    END
                    ||
                    CASE
                        WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_CS' AND DMX.LIST_FFL_CAPTL_EXCH_AMT_PRI IS NOT NULL THEN ','|| DMX.LIST_FFL_CAPTL_EXCH_AMT_PRI
                        ELSE NULL
                    END
                    ||
                    CASE
                        WHEN (DMX.THD_TRD_CLASS_SRC_NAME LIKE 'CRD%' OR (DMX.THD_FGT_GRP IN('RTRN','TRS','IRS','CS') AND DMX.UPI LIKE 'Credit%')) AND DMX.LIST_FFL_PYMT_AMT_MOP IS NOT NULL THEN ',' || DMX.LIST_FFL_PYMT_AMT_MOP
                        ELSE NULL
                    END
                )) AS OTH_PAYMENT_AMOUNT,

                TRIM(',' FROM (
                    CASE
                        WHEN DMX.THD_TRD_CLASS_SRC_NAME IN('CRD_CDS','CRD_CRDI','IRD_IRS','IRD_CS') AND NVL(DMX.THD_TYPOLOGY_DESC,' ') != 'Bespoke CDS' AND NVL(DMX.THD_INITIALPAYMENT_AMT, 0) != 0 THEN DECODE(DMX.THD_PREMIUMCCY,'CNH','CNY',DMX.THD_PREMIUMCCY)
                        ELSE NULL
                    END
                    ||
                    CASE
                        WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_RTRN_SWAP' AND DMX.LIST_FFL_PMT_CCY_CODE_RPL_P IS NOT NULL THEN ',' || DMX.LIST_FFL_PMT_CCY_CODE_RPL_P
                        ELSE NULL
                    END
                    ||
                    CASE
                        WHEN DMX.THD_TYPOLOGY_DESC = 'Bespoke CDS' AND DMX.LIST_FFL_PMT_CCY_CODE_LNBR_CDS IS NOT NULL THEN ',' || DMX.LIST_FFL_PMT_CCY_CODE_LNBR_CDS
                        ELSE NULL
                    END
                    ||
                    CASE
                        WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_CS' AND DMX.LIST_FFL_FLOW_CCY_CODE_PRI IS NOT NULL THEN ',' || DMX.LIST_FFL_FLOW_CCY_CODE_PRI
                        ELSE NULL
                    END
                    ||
                    CASE
                        WHEN (DMX.THD_TRD_CLASS_SRC_NAME LIKE 'CRD%' OR (DMX.THD_FGT_GRP IN('RTRN','TRS','IRS','CS') AND DMX.UPI LIKE 'Credit%')) AND DMX.LIST_FFL_PMT_CCY_CODE_MOP IS NOT NULL THEN ',' || DMX.LIST_FFL_PMT_CCY_CODE_MOP
                        ELSE NULL
                    END
                )) AS OTH_PAYMENT_CURR,

                TRIM(',' FROM (
                    CASE
                        WHEN DMX.THD_TRD_CLASS_SRC_NAME IN('CRD_CDS','CRD_CRDI','IRD_IRS','IRD_CS') AND NVL(DMX.THD_TYPOLOGY_DESC,' ') != 'Bespoke CDS' AND NVL(DMX.THD_INITIALPAYMENT_AMT, 0) != 0 THEN TO_CHAR(DMX.THD_PREMIUM_PAY_DATE,'YYYY-MM-DD')
                        ELSE NULL
                    END
                    ||
                    CASE
                        WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_RTRN_SWAP' AND DMX.LIST_FFL_PMT_DATE_RPL_P IS NOT NULL THEN ',' || DMX.LIST_FFL_PMT_DATE_RPL_P
                        ELSE NULL
                    END
                    ||
                    CASE
                        WHEN DMX.THD_TYPOLOGY_DESC = 'Bespoke CDS'  AND DMX.LIST_FFL_PMT_DATE_LNBR_CDS IS NOT NULL THEN ',' || DMX.LIST_FFL_PMT_DATE_LNBR_CDS
                        ELSE NULL
                    END
                    ||
                    CASE
                        WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_CS' AND DMX.LIST_FFL_FLOW_PYMT_DATE_PRI IS NOT NULL THEN ',' || DMX.LIST_FFL_FLOW_PYMT_DATE_PRI
                        ELSE NULL
                    END
                    ||
                    CASE
                        WHEN (DMX.THD_TRD_CLASS_SRC_NAME LIKE 'CRD%' OR (DMX.THD_FGT_GRP IN('RTRN','TRS','IRS','CS') AND DMX.UPI LIKE 'Credit%')) AND DMX.LIST_FFL_PMT_DATE_MOP IS NOT NULL THEN ',' || DMX.LIST_FFL_PMT_DATE_MOP
                        ELSE NULL
                    END
                )) AS OTH_PAYMENT_DATE,

                TRIM(',' FROM (
                    CASE
                        WHEN DMX.THD_TRD_CLASS_SRC_NAME IN('CRD_CDS','CRD_CRDI','IRD_IRS','IRD_CS') AND NVL(DMX.THD_TYPOLOGY_DESC,' ') != 'Bespoke CDS' AND NVL(DMX.THD_INITIALPAYMENT_AMT, 0) != 0 THEN
                            CASE
                                WHEN DMX.THD_INITIALPAYMENT_AMT < 0 THEN DMX.REPORTING_PARTY_LEI
                                ELSE DMX.COUNTERPARTY_LEI
                            END
                        ELSE NULL
                    END
                    ||
                    CASE
                        WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_RTRN_SWAP' AND DMX.LIST_FFL_PMT_PAY_LEI_RPL_P IS NOT NULL THEN ',' || DMX.LIST_FFL_PMT_PAY_LEI_RPL_P
                        ELSE NULL
                    END
                    ||
                    CASE
                        WHEN DMX.THD_TYPOLOGY_DESC = 'Bespoke CDS' AND DMX.LIST_FFL_PMT_PAY_LEI_LNBR_CDS IS NOT NULL THEN ',' || DMX.LIST_FFL_PMT_PAY_LEI_LNBR_CDS
                        ELSE NULL
                    END
                    ||
                    CASE
                        WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_CS' AND DMX.LIST_FFL_RPY_LEI_PRI_PAY IS NOT NULL THEN ',' || DMX.LIST_FFL_RPY_LEI_PRI_PAY
                        ELSE NULL
                    END
                    ||
                    CASE
                        WHEN (DMX.THD_TRD_CLASS_SRC_NAME LIKE 'CRD%' OR (DMX.THD_FGT_GRP IN('RTRN','TRS','IRS','CS') AND DMX.UPI LIKE 'Credit%')) AND DMX.LIST_FFL_PMT_PAY_LEI_MOP IS NOT NULL THEN ',' || DMX.LIST_FFL_PMT_PAY_LEI_MOP
                        ELSE NULL
                    END
                )) AS OTH_PAYMENT_PAYER,

                TRIM(',' FROM (
                    CASE
                        WHEN DMX.THD_TRD_CLASS_SRC_NAME IN('CRD_CDS','CRD_CRDI','IRD_IRS','IRD_CS') AND NVL(DMX.THD_TYPOLOGY_DESC,' ') != 'Bespoke CDS' AND NVL(DMX.THD_INITIALPAYMENT_AMT, 0) != 0 THEN
                            CASE
                                WHEN DMX.THD_INITIALPAYMENT_AMT > 0 THEN DMX.REPORTING_PARTY_LEI
                                ELSE DMX.COUNTERPARTY_LEI
                            END
                        ELSE NULL
                    END
                    ||
                    CASE
                        WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_RTRN_SWAP' AND DMX.LIST_FFL_PMT_RECV_LEI_RPL_P IS NOT NULL THEN ',' || DMX.LIST_FFL_PMT_RECV_LEI_RPL_P
                        ELSE NULL
                    END
                    ||
                    CASE
                        WHEN DMX.THD_TYPOLOGY_DESC = 'Bespoke CDS' AND DMX.LIST_FFL_PMT_RECV_LEI_LNBR_CDS IS NOT NULL THEN ',' || DMX.LIST_FFL_PMT_RECV_LEI_LNBR_CDS
                        ELSE NULL
                    END
                    ||
                    CASE
                        WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_CS' AND DMX.LIST_FFL_RPY_LEI_PRI_RECV IS NOT NULL THEN ',' || DMX.LIST_FFL_RPY_LEI_PRI_RECV
                        ELSE NULL
                    END
                    ||
                    CASE
                        WHEN (DMX.THD_TRD_CLASS_SRC_NAME LIKE 'CRD%' OR (DMX.THD_FGT_GRP IN('RTRN','TRS','IRS','CS') AND DMX.UPI LIKE 'Credit%')) AND DMX.LIST_FFL_PMT_RECV_LEI_MOP IS NOT NULL THEN ',' || DMX.LIST_FFL_PMT_RECV_LEI_MOP
                        ELSE NULL
                    END
                )) AS OTH_PAYMENT_RECEIVER,

                TRIM(',' FROM (
                    CASE
                        WHEN DMX.THD_TRD_CLASS_SRC_NAME IN('CRD_CDS','CRD_CRDI','IRD_IRS','IRD_CS') AND NVL(DMX.THD_TYPOLOGY_DESC,' ') != 'Bespoke CDS' AND NVL(DMX.THD_INITIALPAYMENT_AMT, 0) != 0 THEN
                            CASE
                                WHEN DMX.THD_INITIALPAYMENT_AMT < 0 THEN 'LEI'
                                ELSE DMX.PARTY_TYP2
                            END
                        ELSE NULL
                    END
                    ||
                    CASE
                        WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_RTRN_SWAP' AND DMX.LIST_FFL_PMT_PAY_TYPE_RPL_P IS NOT NULL THEN ',' || DMX.LIST_FFL_PMT_PAY_TYPE_RPL_P
                        ELSE NULL
                    END
                    ||
                    CASE
                        WHEN DMX.THD_TYPOLOGY_DESC = 'Bespoke CDS' AND DMX.LIST_FFL_PMT_PAY_TYPE_LNBR_CDS IS NOT NULL THEN ',' || DMX.LIST_FFL_PMT_PAY_TYPE_LNBR_CDS
                        ELSE NULL
                    END
                    ||
                    CASE
                        WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_CS' AND DMX.LIST_FFL_PRI_INIT_FIN_PAY_TYPE IS NOT NULL THEN ',' || DMX.LIST_FFL_PRI_INIT_FIN_PAY_TYPE
                        ELSE NULL
                    END
                    ||
                    CASE
                        WHEN (DMX.THD_TRD_CLASS_SRC_NAME LIKE 'CRD%' OR (DMX.THD_FGT_GRP IN ('RTRN','TRS','IRS','CS') AND DMX.UPI LIKE 'Credit%')) AND DMX.LIST_FFL_PAY_TYPE_MOP IS NOT NULL THEN ',' || DMX.LIST_FFL_PAY_TYPE_MOP
                        ELSE NULL
                    END
                )) AS OTH_PAYMENT_PAYER_TYPE,

                TRIM(',' FROM (
                    CASE
                        WHEN DMX.THD_TRD_CLASS_SRC_NAME IN('CRD_CDS','CRD_CRDI','IRD_IRS','IRD_CS') AND NVL(DMX.THD_INITIALPAYMENT_AMT, 0) != 0 THEN
                            CASE
                                WHEN DMX.THD_INITIALPAYMENT_AMT > 0 THEN 'LEI'
                                ELSE DMX.PARTY_TYP2
                            END
                        ELSE NULL
                    END
                    ||
                    CASE
                        WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_RTRN_SWAP' AND DMX.LIST_FFL_PMT_RECV_TYPE_RPL_P IS NOT NULL THEN ',' || DMX.LIST_FFL_PMT_RECV_TYPE_RPL_P
                        ELSE NULL
                    END
                    ||
                    CASE
                        WHEN DMX.THD_TYPOLOGY_DESC = 'Bespoke CDS' AND DMX.LIST_FFL_PMT_RECV_TYPE_LNBR_CDS IS NOT NULL THEN ',' || DMX.LIST_FFL_PMT_RECV_TYPE_LNBR_CDS
                        ELSE NULL
                    END
                    ||
                    CASE
                        WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_CS' AND DMX.LIST_FFL_PRI_INIT_FIN_RECV_TYPE IS NOT NULL THEN ',' || DMX.LIST_FFL_PRI_INIT_FIN_RECV_TYPE
                        ELSE NULL
                    END
                    ||
                    CASE
                        WHEN (DMX.THD_TRD_CLASS_SRC_NAME LIKE 'CRD%' OR (DMX.THD_FGT_GRP IN ('RTRN','TRS','IRS','CS') AND DMX.UPI LIKE 'Credit%')) AND DMX.LIST_FFL_RECV_TYPE_MOP IS NOT NULL THEN ',' || DMX.LIST_FFL_RECV_TYPE_MOP
                        ELSE NULL
                    END
                )) AS OTH_PAYMENT_RECEIVER_TYPE
            FROM DUAL
		) sub_oth_fields
		--<GH_Rewrite_Work>
		CROSS APPLY
		(
            SELECT
                CASE
                    WHEN DMX.THD_FAMILY = 'CRD' OR  DMX.THD_TRD_CLASS_SRC_NAME IN('IRD_IRS','IRD_CS') THEN 'Credit'
                    WHEN DMX.THD_TRD_CLASS_SRC_NAME = 'IRD_TRS' OR DMX.THD_TRD_CLASS_SRC_NAME LIKE 'IRD_RTRN%' THEN
                        CASE
                            WHEN DMX.THD_CONTRCT_TYPOLOGY_VAL LIKE 'IR TRS%' AND DMX.THD_SEC_GRP_VAL = 'Bond' AND DMX.RPY_LEI_NO_ISSR = '254900HROIFWPRGM1V77' THEN 'Rates'
                            ELSE 'Credit'
                        END
                    ELSE NULL
                END AS UPI_ASSET_CLASS
            FROM DUAL
		) sub_upi_fields
		CROSS APPLY
		(
            SELECT
                --rework of the rework of the rework... maintenant ils veulent CFTC clearable pour CAN clearable aussi...
                CFTC_CLEARABLE,
                CFTC_CLEARABLE AS CAN_CLEARABLE
            FROM
            (
                SELECT
                    CASE
                        WHEN sub_upi_fields.UPI_ASSET_CLASS = 'Credit' AND sub_product.UPI_PRODUCT = 'Index' AND sub_undrlng_instr_term.UPI_UNDRLNG_INSTR_TERM_UNT = 'YEAR' THEN
                            CASE
                                WHEN sub_undrlng_instr.UPI_UNDRLNG_INSTR_INDX = 'CDX.NA.IG' THEN
                                    CASE
                                        WHEN sub_undrlng_instr_term.UPI_UNDRLNG_INSTR_TERM_VAL = '3' AND LPAD(TRIM(sub_undrlng_crd_indx.UPI_UNDRLNG_CRD_INDX_SERIES),10,'0') >= '0000000015' THEN 'Y'
                                        WHEN sub_undrlng_instr_term.UPI_UNDRLNG_INSTR_TERM_VAL = '5' AND LPAD(TRIM(sub_undrlng_crd_indx.UPI_UNDRLNG_CRD_INDX_SERIES),10,'0') >= '0000000011' THEN 'Y'
                                        WHEN sub_undrlng_instr_term.UPI_UNDRLNG_INSTR_TERM_VAL = '7' AND LPAD(TRIM(sub_undrlng_crd_indx.UPI_UNDRLNG_CRD_INDX_SERIES),10,'0') >= '0000000008' THEN 'Y'
                                        WHEN sub_undrlng_instr_term.UPI_UNDRLNG_INSTR_TERM_VAL = '10' AND LPAD(TRIM(sub_undrlng_crd_indx.UPI_UNDRLNG_CRD_INDX_SERIES),10,'0') >= '0000000008' THEN 'Y'
                                        ELSE 'N'
                                    END
                                WHEN sub_undrlng_instr.UPI_UNDRLNG_INSTR_INDX = 'CDX.NA.HY' THEN
                                    CASE
                                        WHEN sub_undrlng_instr_term.UPI_UNDRLNG_INSTR_TERM_VAL = '5' AND LPAD(TRIM(sub_undrlng_crd_indx.UPI_UNDRLNG_CRD_INDX_SERIES),10,'0') >= '0000000011' THEN 'Y'
                                        ELSE 'N'
                                    END
                                WHEN sub_undrlng_instr.UPI_UNDRLNG_INSTR_INDX = 'iTRAXX EUROPE' THEN
                                    CASE
                                        WHEN sub_undrlng_instr_term.UPI_UNDRLNG_INSTR_TERM_VAL = '5' AND LPAD(TRIM(sub_undrlng_crd_indx.UPI_UNDRLNG_CRD_INDX_SERIES),10,'0') >= '0000000010' THEN 'Y'
                                        WHEN sub_undrlng_instr_term.UPI_UNDRLNG_INSTR_TERM_VAL = '10' AND LPAD(TRIM(sub_undrlng_crd_indx.UPI_UNDRLNG_CRD_INDX_SERIES),10,'0') >= '0000000007' THEN 'Y'
                                        ELSE 'N'
                                    END
                                WHEN sub_undrlng_instr.UPI_UNDRLNG_INSTR_INDX = 'iTRAXX EUROPE CROSSOVER' THEN
                                    CASE
                                        WHEN sub_undrlng_instr_term.UPI_UNDRLNG_INSTR_TERM_VAL = '5' AND LPAD(TRIM(sub_undrlng_crd_indx.UPI_UNDRLNG_CRD_INDX_SERIES),10,'0') >= '0000000010' THEN 'Y'
                                        ELSE 'N'
                                    END
                                WHEN sub_undrlng_instr.UPI_UNDRLNG_INSTR_INDX = 'iTRAXX EUROPE HIVOL' THEN
                                    CASE
                                        WHEN sub_undrlng_instr_term.UPI_UNDRLNG_INSTR_TERM_VAL = '5' AND LPAD(TRIM(sub_undrlng_crd_indx.UPI_UNDRLNG_CRD_INDX_SERIES),10,'0') >= '0000000010' THEN 'Y'
                                        ELSE 'N'
                                    END
                                ELSE 'N'
                            END
                        ELSE 'N'
                    END AS CFTC_CLEARABLE
                FROM DUAL
            ) bruh
		) sub_clearable
		--</GH_Rewrite_Work>
		--UPI 10 CREDIT/SWAP/CORPORATE
		LEFT JOIN UPI_ANNA_DSB UPI_SWP_CORP ON
			UPI_SWP_CORP.UPI_INT_IDX = 'Credit'
			AND	UPI_SWP_CORP.UPI_INT_CODE = 'Swap:Corporate'
			AND UPI_SWP_CORP.UPI_UNDERLYING_INSTR_CODE = NVL(sub_undrlng_instr.UPI_UNDRLNG_INSTR_ISIN, ' ')
			AND UPI_SWP_CORP.UPI_UNDERLYING_ISSUER_LEI = NVL(sub_undrlng_instr.UPI_UNDRLNG_INSTR_LEI, ' ')
			AND UPPER(UPI_SWP_CORP.UPI_TERM_CONTRACT) = NVL(REPLACE(UPPER(sub_contract_spec.UPI_CONTRACT_SPEC),' ',''), ' ')
			AND UPI_SWP_CORP.UPI_BOND_SENIORITY = NVL(sub_debt_seniority.UPI_DEBT_SENIORITY, ' ')
			AND UPI_SWP_CORP.UPI_DELIVERY_TYPE = NVL(sub_delivery_type.UPI_DELIVERY_TYPE, ' ')
			--AND sub_instrument.UPI_INSTRUMENT_TYPE = 'Swap'
			AND sub_product.UPI_PRODUCT = 'Corporate'
		--UPI 168 CREDIT/SWAP/SOVEREIGN
		LEFT JOIN UPI_ANNA_DSB UPI_SWP_SOV ON
			UPI_SWP_SOV.UPI_INT_IDX = 'Credit'
			AND	UPI_SWP_SOV.UPI_INT_CODE = 'Swap:Sovereign'
			AND UPI_SWP_SOV.UPI_UNDERLYING_INSTR_CODE = NVL(sub_undrlng_instr.UPI_UNDRLNG_INSTR_ISIN, ' ')
			AND UPI_SWP_SOV.UPI_UNDERLYING_ISSUER_LEI = NVL(sub_undrlng_instr.UPI_UNDRLNG_INSTR_LEI, ' ')
			AND UPPER(UPI_SWP_SOV.UPI_TERM_CONTRACT) = NVL(REPLACE(UPPER(sub_contract_spec.UPI_CONTRACT_SPEC),' ',''), ' ')
			AND UPI_SWP_SOV.UPI_BOND_SENIORITY = NVL(sub_debt_seniority.UPI_DEBT_SENIORITY, ' ')
			AND UPI_SWP_SOV.UPI_DELIVERY_TYPE = NVL(sub_delivery_type.UPI_DELIVERY_TYPE, ' ')
			--AND sub_instrument.UPI_INSTRUMENT_TYPE = 'Swap'
			AND sub_product.UPI_PRODUCT = 'Sovereign'
		--UPI 169 CREDIT/SWAP/MUNICIPAL
		LEFT JOIN UPI_ANNA_DSB UPI_SWP_MUNI ON
			UPI_SWP_MUNI.UPI_INT_IDX = 'Credit'
			AND	UPI_SWP_MUNI.UPI_INT_CODE = 'Swap:Municipal'
			AND UPI_SWP_MUNI.UPI_UNDERLYING_INSTR_CODE = NVL(sub_undrlng_instr.UPI_UNDRLNG_INSTR_ISIN, ' ')
			AND UPI_SWP_MUNI.UPI_UNDERLYING_ISSUER_LEI = NVL(sub_undrlng_instr.UPI_UNDRLNG_INSTR_LEI, ' ')
			AND UPPER(UPI_SWP_MUNI.UPI_TERM_CONTRACT) = NVL(REPLACE(UPPER(sub_contract_spec.UPI_CONTRACT_SPEC),' ',''), ' ')
			AND UPI_SWP_MUNI.UPI_BOND_SENIORITY = NVL(sub_debt_seniority.UPI_DEBT_SENIORITY, ' ')
			AND UPI_SWP_MUNI.UPI_DELIVERY_TYPE = NVL(sub_delivery_type.UPI_DELIVERY_TYPE, ' ')
			--AND sub_instrument.UPI_INSTRUMENT_TYPE = 'Swap'
			AND sub_product.UPI_PRODUCT = 'Municipal'
		--UPI 187 CREDIT/SWAP/LOAN
		LEFT JOIN UPI_ANNA_DSB UPI_SWP_LOAN ON
			UPI_SWP_LOAN.UPI_INT_IDX = 'Credit'
			AND	UPI_SWP_LOAN.UPI_INT_CODE = 'Swap:Loan'
			AND UPI_SWP_LOAN.UPI_UNDERLYING_INSTR_CODE = NVL(sub_undrlng_instr.UPI_UNDRLNG_INSTR_ISIN, ' ')
			AND UPI_SWP_LOAN.UPI_UNDERLYING_ISSUER_LEI = NVL(sub_undrlng_instr.UPI_UNDRLNG_INSTR_LEI, ' ')
			AND UPPER(UPI_SWP_LOAN.UPI_TERM_CONTRACT) = NVL(REPLACE(UPPER(sub_contract_spec.UPI_CONTRACT_SPEC),' ',''), ' ')
			AND UPI_SWP_LOAN.UPI_BOND_SENIORITY = NVL(sub_debt_seniority.UPI_DEBT_SENIORITY, ' ')
			AND UPI_SWP_LOAN.UPI_DELIVERY_TYPE = NVL(sub_delivery_type.UPI_DELIVERY_TYPE, ' ')
			--AND sub_instrument.UPI_INSTRUMENT_TYPE = 'Swap'
			AND sub_product.UPI_PRODUCT = 'Loan'
		--UPI 194 CREDIT/SWAP/INDEX
		LEFT JOIN UPI_ANNA_DSB UPI_SWP_IDX ON
			UPI_SWP_IDX.UPI_INT_IDX = 'Credit'
			AND	UPI_SWP_IDX.UPI_INT_CODE = 'Swap:Index'
			AND UPI_SWP_IDX.UPI_UNDERLYING_INDEX_NAME = NVL(sub_undrlng_instr.UPI_UNDRLNG_INSTR_INDX, ' ')
			AND UPPER(UPI_SWP_IDX.UPI_TERM_CONTRACT) = NVL(REPLACE(UPPER(sub_contract_spec.UPI_CONTRACT_SPEC),' ',''), ' ')
			AND UPI_SWP_IDX.UPI_BOND_SENIORITY = NVL(sub_debt_seniority.UPI_DEBT_SENIORITY, ' ')
			AND UPI_SWP_IDX.UPI_DELIVERY_TYPE = NVL(sub_delivery_type.UPI_DELIVERY_TYPE, ' ')
			AND UPI_SWP_IDX.UPI_UNDERLYING_INDEX_TERM_VAL = NVL(sub_undrlng_instr_term.UPI_UNDRLNG_INSTR_TERM_VAL, ' ')
			AND UPI_SWP_IDX.UPI_UNDERLYING_INDEX_TERM_UNT = NVL(substr(sub_undrlng_instr_term.UPI_UNDRLNG_INSTR_TERM_UNT,1,1), ' ')
			AND UPI_SWP_IDX.UPI_INDEX_SERIES = NVL(sub_undrlng_crd_indx.UPI_UNDRLNG_CRD_INDX_SERIES, ' ')
			AND UPI_SWP_IDX.UPI_INDEX_VERSION = NVL(sub_undrlng_crd_indx.UPI_UNDRLNG_CRD_INDX_VERSION, ' ')
			AND UPI_SWP_IDX.UPI_UNDERLYING_ISSUER_TYPE = NVL(sub_undrlng_issr.UPI_UNDRLNG_ISSUER_TYPE, ' ')
			--AND sub_instrument.UPI_INSTRUMENT_TYPE = 'Swap'
			AND sub_product.UPI_PRODUCT = 'Index'
		--UPI 215 CREDIT/SWAP/TOTAL_RETURN_SWAP
		LEFT JOIN UPI_ANNA_DSB UPI_SWP_TRS ON
			UPI_SWP_TRS.UPI_INT_IDX = 'Credit'
			AND	UPI_SWP_TRS.UPI_INT_CODE = 'Swap:Total_Return_Swap'
			AND UPI_SWP_TRS.UPI_UNDERLYING_INSTR_CODE = NVL(sub_undrlng_instr.UPI_UNDRLNG_INSTR_ISIN, ' ')
			AND UPI_SWP_TRS.UPI_UNDERLYING_ISSUER_LEI = NVL(sub_undrlng_instr.UPI_UNDRLNG_INSTR_LEI, ' ')
			AND UPI_SWP_TRS.UPI_UNDERLYING_INDEX_NAME = NVL(sub_undrlng_instr.UPI_UNDRLNG_INSTR_INDX, ' ')
			AND UPI_SWP_TRS.UPI_BOND_SENIORITY = NVL(sub_debt_seniority.UPI_DEBT_SENIORITY, ' ')
			AND UPI_SWP_TRS.UPI_DELIVERY_TYPE = NVL(sub_delivery_type.UPI_DELIVERY_TYPE, ' ')
			--AND sub_instrument.UPI_INSTRUMENT_TYPE = 'Swap'
			AND sub_product.UPI_PRODUCT = 'Total_Return_Swap'
		--UPI 222 CREDIT/OPTION/SINGLE_NAME_SWAPTION
		LEFT JOIN UPI_ANNA_DSB UPI_OPT_SNS ON
			UPI_OPT_SNS.UPI_INT_IDX = 'Credit'
			AND	UPI_OPT_SNS.UPI_INT_CODE = 'Option:Single_Name_Swaption'
			AND UPI_OPT_SNS.UPI_UNDERLYING_ID = COALESCE(UPI_SWP_CORP.UPI_UNIQUE_PRD_ID, UPI_SWP_SOV.UPI_UNIQUE_PRD_ID, UPI_SWP_MUNI.UPI_UNIQUE_PRD_ID, UPI_SWP_LOAN.UPI_UNIQUE_PRD_ID, UPI_SWP_IDX.UPI_UNIQUE_PRD_ID, UPI_SWP_TRS.UPI_UNIQUE_PRD_ID)
			--AND UPI_OPT_SNS.UPI_EXERCISE_STYLE = NVL(sub_exercise.UPI_OPTION_EXERCISE_STYLE, ' ')
			--AND UPI_OPT_SNS.UPI_OPTION_TYPE = NVL(sub_option_type.UPI_OPTION_TYPE, ' ')
			--AND UPI_OPT_SNS.UPI_INDEX_TYPE = NVL(sub_valuation_method.UPI_VALUATION_METHOD_TRIGGER, ' ')
			AND UPI_OPT_SNS.UPI_DELIVERY_TYPE = NVL(sub_delivery_type.UPI_DELIVERY_TYPE, ' ')
			AND sub_instrument.UPI_INSTRUMENT_TYPE = 'Option'
			--AND sub_product.UPI_PRODUCT = 'Single_Name_Swaption'
		--UPI 226 CREDIT/OPTION/INDEX_SWAPTION
		LEFT JOIN UPI_ANNA_DSB UPI_OPT_IDXS ON
			UPI_OPT_IDXS.UPI_INT_IDX = 'Credit'
			AND	UPI_OPT_IDXS.UPI_INT_CODE = 'Option:Index_Swaption'
			AND UPI_OPT_IDXS.UPI_UNDERLYING_ID = COALESCE(UPI_SWP_CORP.UPI_UNIQUE_PRD_ID, UPI_SWP_SOV.UPI_UNIQUE_PRD_ID, UPI_SWP_MUNI.UPI_UNIQUE_PRD_ID, UPI_SWP_LOAN.UPI_UNIQUE_PRD_ID, UPI_SWP_IDX.UPI_UNIQUE_PRD_ID, UPI_SWP_TRS.UPI_UNIQUE_PRD_ID)
			--AND UPI_OPT_IDXS.UPI_EXERCISE_STYLE = NVL(sub_exercise.UPI_OPTION_EXERCISE_STYLE, ' ')
			--AND UPI_OPT_IDXS.UPI_OPTION_TYPE = NVL(sub_option_type.UPI_OPTION_TYPE, ' ')
			--AND UPI_OPT_IDXS.UPI_INDEX_TYPE = NVL(sub_valuation_method.UPI_VALUATION_METHOD_TRIGGER, ' ')
			AND UPI_OPT_IDXS.UPI_DELIVERY_TYPE = NVL(sub_delivery_type.UPI_DELIVERY_TYPE, ' ')
			AND sub_instrument.UPI_INSTRUMENT_TYPE = 'Option'
			--AND sub_product.UPI_PRODUCT = 'Index_Swaption'
		--UPI 355 CREDIT/SWAP/NON_STANDARD
		LEFT JOIN UPI_ANNA_DSB UPI_SWP_NSTD ON
			UPI_SWP_NSTD.UPI_INT_IDX = 'Credit'
			AND	UPI_SWP_NSTD.UPI_INT_CODE = 'Swap:Non_Standard'
			AND UPI_SWP_NSTD.UPI_UNDERLYING_INSTR_CODE = NVL(sub_undrlng_instr.UPI_UNDRLNG_INSTR_ISIN, ' ')
			AND UPI_SWP_NSTD.UPI_UNDERLYING_ISSUER_LEI = NVL(sub_undrlng_instr.UPI_UNDRLNG_INSTR_LEI, ' ')
			AND UPI_SWP_NSTD.UPI_UNDERLYING_INDEX_NAME = NVL(sub_undrlng_instr.UPI_UNDRLNG_INSTR_INDX, ' ')
			AND UPPER(UPI_SWP_NSTD.UPI_TERM_CONTRACT) = NVL(REPLACE(UPPER(sub_contract_spec.UPI_CONTRACT_SPEC),' ',''), ' ')
			AND UPI_SWP_NSTD.UPI_BOND_SENIORITY = NVL(sub_debt_seniority.UPI_DEBT_SENIORITY, ' ')
			AND UPI_SWP_NSTD.UPI_DELIVERY_TYPE = NVL(sub_delivery_type.UPI_DELIVERY_TYPE, ' ')
			AND UPI_SWP_NSTD.UPI_UNDERLYING_INDEX_TERM_VAL = NVL(sub_undrlng_instr_term.UPI_UNDRLNG_INSTR_TERM_VAL, ' ')
			AND UPI_SWP_NSTD.UPI_UNDERLYING_INDEX_TERM_UNT = NVL(substr(sub_undrlng_instr_term.UPI_UNDRLNG_INSTR_TERM_UNT,1,1), ' ')
			AND UPI_SWP_NSTD.UPI_INDEX_SERIES = NVL(sub_undrlng_crd_indx.UPI_UNDRLNG_CRD_INDX_SERIES, ' ')
			AND UPI_SWP_NSTD.UPI_INDEX_VERSION = NVL(sub_undrlng_crd_indx.UPI_UNDRLNG_CRD_INDX_VERSION, ' ')
			AND UPI_SWP_NSTD.UPI_UNDERLYING_ISSUER_TYPE = NVL(sub_undrlng_issr.UPI_UNDRLNG_ISSUER_TYPE, ' ')
			AND UPI_SWP_NSTD.UPI_RETURN_OR_PAYOUT_TRIG = NVL(sub_return_payout_trigger.UPI_RETURN_PAYOUT_TRIGGER, ' ')
			AND UPI_SWP_NSTD.UPI_UNDERLYING_ASSET_TYPE = NVL(sub_undrlng_asset_type.UPI_UNDRLNG_ASSET_TYPE, ' ')
			--AND sub_instrument.UPI_INSTRUMENT_TYPE = 'Swap'
			AND sub_product.UPI_PRODUCT = 'Non_Standard'
)
